const item = $json;

// -----------------------------------------------------------------------------
// 1) Clean context from Normalize Full Draft Context
// -----------------------------------------------------------------------------

const articleId = item.articleId || '';
const articleFields = item.articleFields || {};
const sourceAnalysisFields = item.sourceAnalysisFields || {};

// Article fields
const sourceOutlet = articleFields['Source Outlet'] || '';
const sourceUrl = articleFields['Source URL'] || '';
const sourceTitle = articleFields['Title'] || '';
const sourceDek = articleFields['Dek'] || '';
const sourceBody = articleFields['Source Body / Summary'] || '';

const category = articleFields['Category'] || '';
const subcategory = articleFields['Subcategory'] || '';
const articleType = articleFields['Article Type'] || '';
const notes = articleFields['Notes'] || '';

const includeExistingDraft =
  articleFields['Marked for Regeneration'] === true ||
  articleFields['Marked for Regeneration'] === 'true' ||
  articleFields['Marked for Regeneration'] === 1;

const existingBaadTitle = includeExistingDraft ? (articleFields['BAAD Title'] || '') : '';
const existingBaadDek = includeExistingDraft ? (articleFields['BAAD Dek'] || '') : '';
const existingBaadSummary = includeExistingDraft ? (articleFields['BAAD Editor Summary'] || '') : '';
const existingBaadBody = includeExistingDraft ? (articleFields['Body (BAAD Draft)'] || '') : '';

// -----------------------------------------------------------------------------
// 2) Source-analysis editorial intelligence
// -----------------------------------------------------------------------------

let analysisJson = {};
try {
  analysisJson = item.analysisJsonRaw ? JSON.parse(item.analysisJsonRaw) : {};
} catch (error) {
  analysisJson = {};
}

const leadWith =
  item.leadWith ||
  sourceAnalysisFields['Lead With'] ||
  analysisJson.leadWithNormalized ||
  analysisJson.leadWithRaw ||
  '';

const articleFocusType =
  sourceAnalysisFields['Article Focus Type'] ||
  analysisJson.articleFocusTypeNormalized ||
  analysisJson.articleFocusTypeRaw ||
  '';

const openingStrategy =
  item.openingStrategy ||
  sourceAnalysisFields['Opening Strategy'] ||
  analysisJson.openingStrategy ||
  '';

const mainRisk =
  item.mainRisk ||
  sourceAnalysisFields['Main Risk'] ||
  analysisJson.mainRisk ||
  '';

const sourceStrength =
  item.sourceStrength ||
  sourceAnalysisFields['Source Strength'] ||
  analysisJson.sourceStrength ||
  '';

const sourceAnalysis = {
  sourceAnalysisId: item.sourceAnalysisId || '',

  primaryScenario:
    item.primaryScenario ||
    sourceAnalysisFields['Primary Scenario'] ||
    analysisJson.primaryScenario ||
    '',

  secondaryScenario:
    item.secondaryScenario ||
    sourceAnalysisFields['Secondary Scenario'] ||
    (Array.isArray(analysisJson.secondaryScenarios)
      ? analysisJson.secondaryScenarios.join('; ')
      : '') ||
    '',

  recommendedBaadBlueprint:
    item.recommendedBaadBlueprint ||
    sourceAnalysisFields['Recommended BAAD Blueprint'] ||
    analysisJson.recommendedBlueprint ||
    '',

  recommendedBaadArticleShape:
    item.recommendedBaadArticleShape ||
    sourceAnalysisFields['Recommended BAAD Article Shape'] ||
    '',

  leadWith,

  bestBaadAngle:
    item.bestBaadAngle ||
    sourceAnalysisFields['Best BAAD Angle'] ||
    '',

  mustPreserve:
    item.mustPreserve ||
    sourceAnalysisFields['Must Preserve'] ||
    '',

  avoidOveremphasising:
    item.avoidOveremphasising ||
    sourceAnalysisFields['Avoid Overemphasising'] ||
    '',

  baadAnchorOpeningRule:
    item.baadAnchorOpeningRule ||
    sourceAnalysisFields['BAAD-Anchor Opening Rule'] ||
    '',

  humanReviewReason:
    item.humanReviewReason ||
    sourceAnalysisFields['Human Review Reason'] ||
    '',

  timelinessHookType:
    sourceAnalysisFields['Timeliness Hook Type'] ||
    '',

  timelinessHookDetails:
    sourceAnalysisFields['Timeliness Hook Details'] ||
    '',

  articleFocusType,

  openingStrategy,
  mainRisk,
  sourceStrength,

  exhibitionProjectNames:
    sourceAnalysisFields['Exhibition / Project Names'] ||
    '',

  venueInstitutionNames:
    sourceAnalysisFields['Venue / Institution Names'] ||
    '',

  artistSubjectNames:
    sourceAnalysisFields['Artist / Subject Names'] ||
    '',

  sourceArticleSummary:
    sourceAnalysisFields['Source Article Summary'] ||
    '',

  analysisJson,
};

// -----------------------------------------------------------------------------
// 3) Style blueprint context
// -----------------------------------------------------------------------------

const styleBlueprint = {
  recordId: item.styleBlueprintId || item.blueprintRecordId || '',

  blueprintName:
    item.styleBlueprintName ||
    item.blueprintName ||
    '',

  promptInstructions:
    item.stylePromptInstructions ||
    '',

  openingFormula:
    item.styleOpeningFormula ||
    '',

  paragraphStructure:
    item.styleParagraphStructure ||
    '',

  toneRules:
    item.styleToneRules ||
    '',

  avoidTheseHabits:
    item.styleAvoidTheseHabits ||
    '',

  targetWordCount:
    item.styleTargetWordCount ||
    '',
};

// -----------------------------------------------------------------------------
// 4) Closing paragraph context
// -----------------------------------------------------------------------------

const closingInfo = item.closingInfo || {};

const closingParagraphContext = {
  closingInfoId: closingInfo.closingInfoId || '',
  closingInfoName: closingInfo.closingInfoName || '',

  status: closingInfo.status || '',
  closingParagraphType: closingInfo.closingParagraphType || '',
  useInDraft: closingInfo.useInDraft === true,
  humanReviewNeeded: closingInfo.humanReviewNeeded === true,

  projectExhibitionTitle: closingInfo.projectExhibitionTitle || '',
  venueInstitution: closingInfo.venueInstitution || '',
  cityLocation: closingInfo.cityLocation || '',
  openingDate: closingInfo.openingDate || '',
  closingDate: closingInfo.closingDate || '',
  durationDateText: closingInfo.durationDateText || '',

  baadExhibitionUrl: closingInfo.baadExhibitionUrl || '',
  baadArtistUrl: closingInfo.baadArtistUrl || '',
  baadGalleryUrl: closingInfo.baadGalleryUrl || '',

  recentArtistActivity: closingInfo.recentArtistActivity || '',
  upcomingArtistActivity: closingInfo.upcomingArtistActivity || '',
  recentCommissionPrizeBookFairExhibition:
    closingInfo.recentCommissionPrizeBookFairExhibition || '',

  artistWebsite: closingInfo.artistWebsite || '',
  artistInstagram: closingInfo.artistInstagram || '',
  galleryPage: closingInfo.galleryPage || '',
  museumInstitutionPage: closingInfo.museumInstitutionPage || '',
  otherRelevantLink: closingInfo.otherRelevantLink || '',

  preferredClosingSentence: closingInfo.preferredClosingSentence || '',
  closingParagraphNotes: closingInfo.closingParagraphNotes || '',
};

// -----------------------------------------------------------------------------
// 5) BAAD Source Packets context
// -----------------------------------------------------------------------------

const sourcePacketsApplied = item.sourcePacketsApplied === true;
const sourcePacketsCount = Number(item.sourcePacketsCount || 0);
const sourcePackets = Array.isArray(item.sourcePackets) ? item.sourcePackets : [];
const sourcePacketsForPrompt = item.sourcePacketsForPrompt || '';
const sourcePacketRoles = item.sourcePacketRoles || {};
const sourcePacketRoleGuide = item.sourcePacketRoleGuide || '';

const sourcePacketsContext = {
  sourcePacketsApplied,
  sourcePacketsCount,
  sourcePackets,
  sourcePacketsForPrompt,
  sourcePacketRoles,
  sourcePacketRoleGuide,

  factualSkeletonPackets: sourcePacketRoles.factualSkeletonPackets || [],
  artistVoicePackets: sourcePacketRoles.artistVoicePackets || [],
  materialProcessPackets: sourcePacketRoles.materialProcessPackets || [],
  contextPackets: sourcePacketRoles.contextPackets || [],
  externalInterpretationPackets: sourcePacketRoles.externalInterpretationPackets || [],
  quotePackets: sourcePacketRoles.quotePackets || [],
  closingPackets: sourcePacketRoles.closingPackets || [],
  highCopyingRiskPackets: sourcePacketRoles.highCopyingRiskPackets || [],
};

// -----------------------------------------------------------------------------
// 6) Final compact context for OpenAI
// -----------------------------------------------------------------------------

const context = {
  articleId,

  source: {
    sourceOutlet,
    sourceUrl,
    sourceTitle,
    sourceDek,
    sourceBody,
    category,
    subcategory,
    articleType,
    notes,
  },

  existingDraftContext: {
    includeExistingDraft,
    existingBaadTitle,
    existingBaadDek,
    existingBaadSummary,
    existingBaadBody,
  },

  sourceAnalysis,

  styleBlueprint,

  closingInfo: closingParagraphContext,

  sourcePackets: sourcePacketsContext,

  workflow: {
    blueprintSelectionReason: item.blueprintSelectionReason || '',
    selectedCategory: item.selectedCategory || '',
    recommendedBlueprint: item.recommendedBlueprint || '',
    closingInfoApplied: item.closingInfoApplied === true,
    closingInfoRecordId: item.closingInfoRecordId || '',
    sourcePacketsApplied,
    sourcePacketsCount,
  },
};


// -----------------------------------------------------------------------------
// 6b) Lightweight Context JSON for OpenAI
// -----------------------------------------------------------------------------
//
// Source Packets are already provided above as approved prompt text.
// Do not repeat the full Source Packet arrays inside Context JSON.

const contextForPromptJson = {
  articleId,

  source: {
    sourceOutlet,
    sourceUrl,
    sourceTitle,
    sourceDek,
    sourceBody,
    category,
    subcategory,
    articleType,
    notes,
  },

  existingDraftContext: {
    includeExistingDraft,
    existingBaadTitle,
    existingBaadDek,
    existingBaadSummary,
    existingBaadBody,
  },

  sourceAnalysis,
  styleBlueprint,
  closingInfo: closingParagraphContext,

  sourcePacketsSummary: {
    sourcePacketsApplied,
    sourcePacketsCount,
    sourcePacketRoleGuide,
  },

  workflow: {
    blueprintSelectionReason: item.blueprintSelectionReason || '',
    selectedCategory: item.selectedCategory || '',
    recommendedBlueprint: item.recommendedBlueprint || '',
    closingInfoApplied: item.closingInfoApplied === true,
    closingInfoRecordId: item.closingInfoRecordId || '',
    sourcePacketsApplied,
    sourcePacketsCount,
  },
};

// -----------------------------------------------------------------------------
// 7) Build final reusable prompt
// -----------------------------------------------------------------------------

const prompt = `
You are an arts writer for Black Art & Design (BAAD).

Write a concise BAAD editorial article using ONLY the factual material in the context JSON.

SOURCE-ANALYSIS PRIORITY:
The "sourceAnalysis" object is not extra source material. It is editorial guidance for how to transform the source into a BAAD article.
You must follow it carefully.

For this article:
- Primary scenario: ${sourceAnalysis.primaryScenario}
- Secondary scenario(s): ${sourceAnalysis.secondaryScenario}
- Recommended article shape: ${sourceAnalysis.recommendedBaadArticleShape}
- Lead with: ${sourceAnalysis.leadWith}
- Article focus type: ${sourceAnalysis.articleFocusType}
- Opening strategy: ${sourceAnalysis.openingStrategy}
- Best BAAD angle: ${sourceAnalysis.bestBaadAngle}
- Source strength: ${sourceAnalysis.sourceStrength}
- Main risk: ${sourceAnalysis.mainRisk}

MUST PRESERVE:
${sourceAnalysis.mustPreserve}

AVOID OVEREMPHASISING:
${sourceAnalysis.avoidOveremphasising}

BAAD-ANCHOR OPENING RULE:
${sourceAnalysis.baadAnchorOpeningRule}

APPROVED BAAD SOURCE PACKETS:
${sourcePacketsApplied && sourcePacketsForPrompt
  ? sourcePacketsForPrompt
  : 'No approved BAAD Source Packets are attached for this article.'}

APPROVED BAAD SOURCE PACKET ROLE PLAN:
${sourcePacketsApplied && sourcePacketRoleGuide
  ? sourcePacketRoleGuide
  : 'No approved BAAD Source Packet role plan is available for this article.'}

SOURCE PACKET RULES:
- If APPROVED BAAD SOURCE PACKETS are provided, use them as structured editorial evidence, not as one undifferentiated source dump.
- Use factual_skeleton packets first for title, venue, city, dates, media, materials, works, collaborators, official project details, and stable exhibition facts.
- Use artist_voice packets for direct artist quotes, motivations, personal context, material meaning, studio/process language, and first-person explanation.
- Use material_process packets to make the article visually and materially specific. Do not replace concrete packet details with vague art language.
- Use context packets only when they help the reader understand the project. Do not let background overwhelm the article.
- Use external_interpretation or high-copying-risk packets cautiously. Treat them as external framing, not BAAD’s own judgement.
- Use quote_pool packets selectively. Quote only when the quote adds something the article cannot say better in original BAAD prose.
- Use closing packets only for practical closing information, such as dates, venue, links, public programme, and official next-step details.
- Source Packets do not replace the origin source body or Source Article Analysis.
- Treat Source Packets as approved supporting evidence that may improve specificity, context, and factual depth.
- Use Prompt-Ready Extract and Verified Facts for safe factual grounding.
- Use Source Meaning to Recast as the originality guide: preserve meaning, but rewrite in BAAD’s own structure and language.
- Use Avoid Copying Notes as hard negative instructions.
- Use Editorial Use Notes to decide each packet’s role in the article.
- Use Quote Candidates and Quote Use Notes as a quote pool, not as mandatory copy.
- Do not copy Source Packet wording directly.
- Do not copy distinctive language from the original source behind the Source Packet.
- If a Source Packet says to recast meaning, preserve the meaning but rewrite it in original BAAD language.
- If a Source Packet says a quote is sensitive, broad, vague, or not recommended, paraphrase carefully or omit it.
- If Source Packets contain more detail than the origin article, you may use that detail only if it is clearly presented as verified context in the packet.
- Do not use the raw Full Text / Extract unless it appears inside the approved Source Packet prompt context.
- Do not add facts merely because they seem likely. Use only facts included in the context JSON.
- For the Yinka Ilori prototype pattern: official/gallery packet = factual skeleton; interview/article packet = artist voice plus high-copying-risk external framing.

STYLE BLUEPRINT:
Use this style blueprint as a structural guide only. It is not a factual source.

Blueprint name:
${styleBlueprint.blueprintName}

Target word count:
${styleBlueprint.targetWordCount}

Opening formula:
${styleBlueprint.openingFormula}

Paragraph structure:
${styleBlueprint.paragraphStructure}

Tone rules:
${styleBlueprint.toneRules}

Avoid these habits:
${styleBlueprint.avoidTheseHabits}

Prompt instructions:
${styleBlueprint.promptInstructions}

CLOSING PARAGRAPH INFO:
Use this object to shape the final paragraph if closingInfo.useInDraft is true and closingInfo.status is not "Do Not Use".

Closing paragraph type:
${closingParagraphContext.closingParagraphType}

Preferred closing sentence:
${closingParagraphContext.preferredClosingSentence}

BAAD internal links:
- BAAD Exhibition URL: ${closingParagraphContext.baadExhibitionUrl}
- BAAD Artist URL: ${closingParagraphContext.baadArtistUrl}
- BAAD Gallery URL: ${closingParagraphContext.baadGalleryUrl}

Verified project/exhibition details:
- Project / exhibition title: ${closingParagraphContext.projectExhibitionTitle}
- Venue / institution: ${closingParagraphContext.venueInstitution}
- City / location: ${closingParagraphContext.cityLocation}
- Opening date: ${closingParagraphContext.openingDate}
- Closing date: ${closingParagraphContext.closingDate}
- Duration / date text: ${closingParagraphContext.durationDateText}

Verified artist activity:
- Recent artist activity: ${closingParagraphContext.recentArtistActivity}
- Upcoming artist activity: ${closingParagraphContext.upcomingArtistActivity}
- Recent commission / prize / book / fair / exhibition: ${closingParagraphContext.recentCommissionPrizeBookFairExhibition}

Verified external links:
- Artist website: ${closingParagraphContext.artistWebsite}
- Artist Instagram: ${closingParagraphContext.artistInstagram}
- Gallery page: ${closingParagraphContext.galleryPage}
- Museum / institution page: ${closingParagraphContext.museumInstitutionPage}
- Other relevant link: ${closingParagraphContext.otherRelevantLink}

Closing paragraph notes:
${closingParagraphContext.closingParagraphNotes}

CLOSING PARAGRAPH RULES:
- If a preferred closing sentence is provided, use it as high-priority guidance for the final paragraph.
- Prioritise BAAD internal links over external links when available.
- If a BAAD Exhibition URL is provided, the closing paragraph may direct readers to read more about the exhibition on BAAD.
- If Artist Instagram is provided and verified, the final sentence may say: “See more from the artist on Instagram.”
- If no verified links, dates, or Instagram are provided, use a verified-context-only close.
- Do not invent links, dates, Instagram accounts, websites, upcoming projects, prizes, venues, or exhibition information.
- Do not use vague endings such as “For further details, visit official channels.”

EDITORIAL RHYTHM FOR VENUE / DATE / PRACTICAL DETAILS:
- Keep venue, city, dates, admission, opening reception, and address facts accurate, but do not write them as listing copy.
- Do not front-load full postal addresses in the first half of the article unless the location itself is editorially meaningful.
- Fold venue, city, and date information into natural editorial sentences.
- Prefer sentences like: “Opening at Cristea Roberts Gallery in London, the exhibition runs from 5 June to 11 July 2026 and brings together more than 20 new and recent works across painting, print, sculpture and sound.”
- Avoid stiff administrative constructions such as: “Cristea Roberts Gallery, 43 Pall Mall, London SW1Y 5JG, will present the show from 5 June to 11 July 2026.”
- Avoid formulaic source-attribution constructions such as: “Cristea Roberts presents it as...” unless attribution is needed for a direct quote, disputed claim, or source-sensitive claim.
- Put full address, admission, reception time, extended hours, and visitor logistics near the final paragraph when they are useful.
- Do not let practical details interrupt the article’s editorial rhythm.
- Preserve required facts, but make the published prose read like an edited BAAD article, not an Airtable record, event listing, press release, or workflow output.

ATTRIBUTION STYLE RULES:
- Do not mechanically write “the gallery notes,” “the exhibition text frames,” “the accompanying statement says,” “the press release states,” “the gallery says,” “the statement notes,” “according to the gallery,” “a gallery statement highlights,” “a gallery statement says,” “the statement highlights,” “the exhibition statement highlights,” “the gallery statement,” or similar source-credit phrases for every sourced idea.
- Avoid the formula “source + verb + idea” unless the sentence contains a direct quote or the source of the interpretation is editorially important.
- Absorb verified facts and verified framing into smooth BAAD editorial prose where appropriate.
- Use explicit attribution only for direct quotes, disputed claims, unusual interpretation, or when the source of the claim matters.
- If using a direct quote, identify the speaker or source briefly and naturally.
- Do not make the article sound academic by repeatedly naming the source of every idea.
- The workflow tracks source grounding internally; the published article does not need visible attribution for every verified fact.
- When a verified source explains a theme, you may write the idea directly in BAAD prose if it is not a direct quote and does not create a legal, factual, or editorial risk.

ARTICLE-SPECIFIC RULES:
- Do not make the article sound like a press release.
- Follow the BAAD-Anchor Opening Rule and opening strategy.
- Name the artist early.
- Name the project, exhibition, venue, or institution early when verified.
- Use the source analysis to decide what to foreground, but use only the source/context JSON for facts.
- If source material is short, keep the draft tighter and more restrained.
- Do not overstate cultural, political, historical, emotional, or formal meaning beyond the source.

DESCRIPTION RULES:
- Use only visual, material, spatial, biographical, historical, and exhibition details that appear in the context JSON.
- Do not invent specific objects, colours, materials, scale, placement, lighting effects, atmosphere, installation layout, visitor pathways, or artwork behaviour.
- Do not use generic art-writing atmosphere to fill gaps.
- Prefer concrete nouns over broad praise.
- Prefer precise factual verbs such as “uses,” “works with,” “draws on,” “presents,” “brings together,” “references,” “extends,” “explores,” and “connects.”
- Avoid unsupported words such as “immersive,” “monumental,” “charged,” “meditative,” “expansive,” “atmospheric,” “radical,” “groundbreaking,” or “transformative” unless directly supported by the context.

THEME RULES:
- Write about themes as explored by the project, not as conclusions the article independently proves.
- Cultural, political, diasporic, historical, or community meaning must be tied to specific verified details.
- Do not invent Black cultural context where the source material does not support it.
- Do not over-explain or flatten the artist’s work into a single message.

FACTUALITY RULES:
- Do not invent dates, quotes, artwork titles, curatorial details, biography, exhibition history, awards, materials, links, or gallery relationships not present in the context.
- If the source lacks an exact URL, author, date, title, or venue page, do not invent it.
- Treat the source body, source analysis, style blueprint, closing info, and source packets differently:
  - Source body = factual source.
  - Source analysis = editorial guidance.
  - Style blueprint = structure/tone guidance.
  - Closing info = verified closing/link guidance.
  - Source packets = approved supporting context and prompt-ready evidence.
- Never use the style blueprint as a factual source.

GLOBAL TRANSFORMATION RULES:
- Do not copy the source wording.
- Do not paraphrase sentence by sentence.
- Do not copy more than 8 consecutive words from the source.
- Do not add unsupported claims.
- When source material is short, be more restrained, not more imaginative.
- Write in BAAD house style: grounded, observant, historically aware, accessible, and attentive to Black, African, and diasporic contexts where supported.

EXISTING DRAFT RULE:
- If "includeExistingDraft" is false, ignore existing BAAD draft fields completely.
- If "includeExistingDraft" is true, use the existing draft only as optional regeneration context.
- Never rely on an existing BAAD draft more than the factual source material.

Return ONLY JSON with EXACTLY this structure:

{
  "baad_title": "string",
  "baad_dek": "string",
  "baad_editor_summary": "string",
  "baad_meta_description": "string",
  "baad_seo_title": "string",
  "baad_tags": ["string", "string"],
  "baad_body": "string"
}

For "baad_body", wrap each paragraph in <p>...</p> and separate paragraphs with \\n\\n.

For "baad_dek":
- Keep the dek factual and restrained.
- Do not use unsupported promotional language.
- Do not claim the work does anything not supported by the context.

Context JSON:

\`\`\`json
${JSON.stringify(contextForPromptJson, null, 2)}
\`\`\`
`;

return {
  json: {
    ...item,
    id: articleId,
    prompt,
    promptContext: contextForPromptJson,
    fullDebugContext: context,
    includeExistingDraft,
    styleBlueprintApplied: Boolean(styleBlueprint.blueprintName),
    styleBlueprintName: styleBlueprint.blueprintName,
    styleBlueprintRecordId: styleBlueprint.recordId,
    sourceAnalysisApplied: Boolean(sourceAnalysis.primaryScenario),
    closingInfoApplied: item.closingInfoApplied === true,
    closingInfoRecordId: item.closingInfoRecordId || '',
    sourcePacketsApplied,
    sourcePacketsCount,
  },
};

// Take OpenAI output and turn it into usable JSON fields.
// This version gets the Airtable Article record ID from Build Draft Prompt,
// not from the old Get Articles for Draft node.

// 1) Get the raw text from the OpenAI node.
// n8n Responses API usually returns: output[0].content[0].text
const raw =
  $json.output?.[0]?.content?.[0]?.text ??
  $json.text ??
  $json.message?.content ??
  '';

// 2) Strip ```json ... ``` fences if they exist.
let cleaned = String(raw || '')
  .replace(/```json/i, '')
  .replace(/```/g, '')
  .trim();

// 3) Parse JSON.
let data;

try {
  data = JSON.parse(cleaned);
} catch (err) {
  throw new Error(
    'Failed to parse LLM JSON: ' + err.message + '\nRaw text:\n' + cleaned
  );
}

// 4) Get the original Airtable Article record ID from Build Draft Prompt.
const promptItems = $items('Build Draft Prompt');
const promptItem = promptItems[$itemIndex];

if (!promptItem) {
  throw new Error(
    `Could not find source item from "Build Draft Prompt" for itemIndex=${$itemIndex}. ` +
    `Available items: ${promptItems.length}`
  );
}

const promptJson = promptItem.json || {};
const recordId = promptJson.id || promptJson.articleId || '';

if (!recordId) {
  throw new Error('Could not determine Airtable Article record ID from Build Draft Prompt output.');
}

// 5) Return the fields we want to pass to Airtable.
return {
  json: {
    id: recordId,

    baad_title: data.baad_title || '',
    baad_dek: data.baad_dek || '',
    baad_editor_summary: data.baad_editor_summary || '',
    baad_meta_description: data.baad_meta_description || '',
    baad_seo_title: data.baad_seo_title || '',
    baad_tags: Array.isArray(data.baad_tags) ? data.baad_tags : [],
    baad_body: data.baad_body || '',

    sourceAnalysisApplied: promptJson.sourceAnalysisApplied === true,
    styleBlueprintApplied: promptJson.styleBlueprintApplied === true,
    styleBlueprintName: promptJson.styleBlueprintName || '',
    styleBlueprintRecordId: promptJson.styleBlueprintRecordId || '',
    sourceAnalysisId: promptJson.sourceAnalysisId || '',

    closingInfoApplied: promptJson.closingInfoApplied === true,
    closingInfoRecordId: promptJson.closingInfoRecordId || '',

    finalBaadBlueprintUsed:
      promptJson.finalBaadBlueprintUsed ||
      promptJson.styleBlueprintRecordId ||
      '',

    blueprintSelectionSource:
      promptJson.blueprintSelectionSource || '',

    blueprintSelectionNotes:
      promptJson.blueprintSelectionNotes ||
      promptJson.blueprintSelectionReason ||
      '',

    recommendedBlueprintRecordId:
      promptJson.recommendedBlueprintRecordId || '',
  },
};

const f = $json.fields || $json || {};

function stripHtml(text) {
  return String(text || '')
    .replace(/<\/p>\s*<p>/gi, '\n\n')
    .replace(/<[^>]+>/g, '')
    .trim();
}

function wordCount(text) {
  const plain = stripHtml(text);
  const matches = plain.match(/\b[\w’'-]+\b/g);
  return matches ? matches.length : 0;
}

const sourceBody = f['Source Body / Summary'] || '';
const sourcesCombined = f['Sources Combined (for LLM)'] || f['Sources Combined'] || '';

const sourceBodyWords = wordCount(sourceBody);
const sourcesCombinedWords = wordCount(sourcesCombined);

const bestSourceWordCount = Math.max(sourceBodyWords, sourcesCombinedWords);
const minimumSourceWords = 100;

const sourceIsLongEnough = bestSourceWordCount >= minimumSourceWords;

const sourceQualityMessage = sourceIsLongEnough
  ? `Source quality passed: ${bestSourceWordCount} source words available.`
  : `Source body too short for reliable BAAD draft generation. Source Body / Summary has ${sourceBodyWords} words. Sources Combined (for LLM) has ${sourcesCombinedWords} words. Minimum required is ${minimumSourceWords} words.`;

return {
  json: {
    ...$json,
    sourceBodyWords,
    sourcesCombinedWords,
    bestSourceWordCount,
    minimumSourceWords,
    sourceIsLongEnough,
    sourceQualityMessage,
  },
};

const item = $json;

const articleFields = item.articleFields || item.fields || item || {};
const sourceAnalysisFields = item.sourceAnalysisFields || {};

const category = Array.isArray(articleFields['Category'])
  ? articleFields['Category'][0]
  : (articleFields['Category'] || item.Category || '');

const categoryNorm = String(category || '').trim().toLowerCase();

function firstLinkedRecordId(value) {
  if (Array.isArray(value)) return value[0] || '';
  if (typeof value === 'string') return value.trim();
  return '';
}

function normaliseName(value) {
  return String(value || '').trim().toLowerCase();
}

function blueprintNameFromRecordId(recordId) {
  const map = {
    'rec7AatEnRtWcPSje': 'BAAD Short Visual Art Spotlight',
    'recuScFkhf9NDOm4Y': 'BAAD Short Visual Design Spotlight',
    'recQNbTBwMaQjcCeT': 'BAAD Public Art / Installation Spotlight',
  };
  return map[recordId] || '';
}

function blueprintRecordIdFromName(name) {
  const norm = normaliseName(name);

  if (norm === 'baad short visual art spotlight') {
    return 'rec7AatEnRtWcPSje';
  }

