// -----------------------------------------------------------------------------
// 3) Helpers
// -----------------------------------------------------------------------------

function asText(value) {
  if (Array.isArray(value)) {
    return value
      .map(asText)
      .filter(Boolean)
      .join('\n\n');
  }

  if (value && typeof value === 'object') {
    return Object.values(value)
      .map(asText)
      .filter(Boolean)
      .join('\n\n');
  }

  if (value === null || value === undefined) return '';
  return String(value);
}

function normaliseSourceBlockForDedupe(value) {
  return String(value || '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function uniqueTextBlocks(blocks) {
  const seen = new Set();
  const out = [];

  for (const block of blocks) {
    const text = asText(block).trim();
    if (!text) continue;

    const key = normaliseSourceBlockForDedupe(text);

    if (!key) continue;
    if (seen.has(key)) continue;

    seen.add(key);
    out.push(text);
  }

  return out;
}

function wordCount(text) {
  return String(text || '')
    .replace(/<[^>]+>/g, ' ')
    .trim()
    .split(/\s+/)
    .filter(Boolean).length;
}

function includesPhrase(textLower, phrase) {
  return textLower.includes(String(phrase).toLowerCase());
}

function findHits(phrases, textLower) {
  return phrases.filter((phrase) => includesPhrase(textLower, phrase));
}

function makeSnippet(text, phrase) {
  const lower = String(text || '').toLowerCase();
  const idx = lower.indexOf(String(phrase).toLowerCase());

  if (idx === -1) return '';

  const start = Math.max(0, idx - 90);
  const end = Math.min(String(text).length, idx + phrase.length + 120);

  return String(text)
    .slice(start, end)
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanString(value) {
  return String(value || '').trim();
}

function normaliseFact(value) {
  return cleanString(value).toLowerCase();
}

function normaliseForMatch(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[’‘]/g, "'")
    .replace(/[“”]/g, '"')
    .replace(/\bu\.s\.\b/g, 'us')
    .replace(/\bu\.s\./g, 'us')
    .replace(/-/g, ' ')
    .replace(/[^\w\s']/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function addRequiredFact(requiredFacts, label, value) {
  if (!value) return;

  if (Array.isArray(value)) {
    const cleaned = value
      .map(v => normaliseFact(v))
      .filter(Boolean);

    if (cleaned.length) {
      requiredFacts.push({
        label,
        mode: 'any',
        acceptable: cleaned,
      });
    }

    return;
  }

  const str = normaliseFact(value);
  if (!str) return;

  requiredFacts.push({
    label,
    mode: 'any',
    acceptable: [str],
  });
}

function splitMustPreserve(value) {
  return String(value || '')
    .split(';')
    .map(s => s.trim())
    .filter(Boolean);
}

function singulariseToken(token) {
  const t = normaliseForMatch(token);

  if (t.endsWith('ies') && t.length > 4) {
    return t.slice(0, -3) + 'y';
  }

  if (t.endsWith('s') && t.length > 3) {
    return t.slice(0, -1);
  }

  return t;
}

function gerundVariants(token) {
  const t = normaliseForMatch(token);
  const variants = new Set([t]);

  if (t.endsWith('ing') && t.length > 5) {
    let root = t.slice(0, -3);

    if (root.length > 2 && root[root.length - 1] === root[root.length - 2]) {
      root = root.slice(0, -1);
    }

    variants.add(root);
    variants.add(`${root}s`);
    variants.add(`${root}ed`);
    variants.add(`${root}e`);
    variants.add(`${root}es`);
  }

  return Array.from(variants).filter(Boolean);
}

function basicVariants(value) {
  const base = normaliseForMatch(value);
  const variants = new Set();

  if (!base) return [];

  variants.add(base);
  variants.add(singulariseToken(base));

  for (const variant of gerundVariants(base)) {
    variants.add(variant);
  }

  return Array.from(variants).filter(Boolean);
}

function makeSlashFact(label, lower) {
  const parts = lower
    .split('/')
    .map(p => normaliseForMatch(p))
    .filter(Boolean);

  const acceptable = new Set();

  acceptable.add(normaliseForMatch(lower));
  acceptable.add(normaliseForMatch(lower.replace(/\//g, ' and ')));
  acceptable.add(normaliseForMatch(lower.replace(/\//g, ' or ')));

  for (const part of parts) {
    for (const variant of basicVariants(part)) {
      acceptable.add(variant);
    }
  }

  return {
    label,
    mode: 'any',
    acceptable: Array.from(acceptable).filter(Boolean),
  };
}

function makeAndFact(label, lower) {
  const parts = lower
    .split(/\s+and\s+/)
    .map(p => normaliseForMatch(p))
    .filter(Boolean);

  const groups = parts.map((part) => {
    const variants = new Set(basicVariants(part));

    const tokens = part.split(/\s+/).filter(Boolean);
    for (const token of tokens) {
      for (const variant of basicVariants(token)) {
        variants.add(variant);
      }
    }

    return Array.from(variants).filter(Boolean);
  });

  return {
    label,
    mode: 'allGroups',
    groups,
  };
}

function significantTokens(value) {
  const stopWords = new Set([
    'a',
    'an',
    'and',
    'are',
    'as',
    'at',
    'by',
    'for',
    'from',
    'in',
    'into',
    'is',
    'it',
    'of',
    'on',
    'or',
    'that',
    'the',
    'their',
    'these',
    'this',
    'to',
    'with',
    'work',
    'works',
    'evocative',
  ]);

  return normaliseForMatch(value)
    .split(/\s+/)
    .map(t => t.trim())
    .filter(t => t.length > 2 && !stopWords.has(t));
}

function makeThresholdFact(label, lower) {
  const tokens = significantTokens(lower);

  return {
    label,
    mode: 'threshold',
    tokens,
    minMatches: Math.max(2, Math.ceil(tokens.length * 0.6)),
  };
}

function makeRequiredFactFromMustPreserve(cleaned) {
  const lower = cleanString(cleaned).toLowerCase();
  const label = `must preserve: ${cleaned}`;

  if (lower.includes('/')) {
    return makeSlashFact(label, lower);
  }

  if (/\s+and\s+/.test(lower)) {
    return makeAndFact(label, lower);
  }

  if (lower.length > 35) {
    return makeThresholdFact(label, lower);
  }

  return {
    label,
    mode: 'any',
    acceptable: basicVariants(lower),
  };
}

function factIsPresent(fact, draftNormalised) {
  if (!fact) return true;

  if (fact.mode === 'allGroups') {
    return (fact.groups || []).every((group) =>
      group.some((phrase) => draftNormalised.includes(normaliseForMatch(phrase)))
    );
  }

  if (fact.mode === 'threshold') {
    const tokens = fact.tokens || [];
    const matches = tokens.filter((token) =>
      draftNormalised.includes(normaliseForMatch(token))
    );

    return matches.length >= (fact.minMatches || 1);
  }

  return (fact.acceptable || []).some((phrase) =>
    draftNormalised.includes(normaliseForMatch(phrase))
  );
}

