    phrase,
    snippet: makeSnippet(text, phrase),
    appearsInSource: includesPhrase(sourceTextLower, phrase),
  }));
}

// -----------------------------------------------------------------------------
// 5) Phrase lists
// -----------------------------------------------------------------------------

const hardBanPhrases = [
  'must-see',
  'not to be missed',
  'groundbreaking',
  'game-changing',
  'masterpiece',
  'iconic artist',
  'important artist',
  'powerful statement',
  'revolutionary',
];

const riskyPhrases = [
  'transforms',
  'immersive',
  'atmosphere',
  'atmospheric',
  'resonant',
  'charged',
  'meditative',
  'monumental',
  'encounter',
  'in conversation with',
  'directly in conversation',
  'carries memory',
  'carry memory',
  'spatial composition',
  'sensory means',
  'sound structures',
  'architecture frame',
  'shaped for the site',
  'sets up a place',
  'sculptural presence',
];

const subtleUnsupportedPhrases = [
  'take centre stage',
  'takes centre stage',
  'take center stage',
  'takes center stage',
  'distinctive architecture',
  'setting the tone',
  'sets the tone',
  'spatial prompt',
  'provides the spatial prompt',
  'works with directly',
  'court’s character',
  "court's character",
  'responding to the court’s character',
  "responding to the court's character",
  'each element positioned',
  'elements positioned',
  'unified site-specific approach',
  'constellation of components',
  'cultural memory',
  'lived experience into the installation',
  'sonic and sculptural language',
  'sculptural language',
  'sonic language',
  'threads cultural memory',
  'threading cultural memory',
  'placed within the architecture',
  'places these elements within',
  'spatial character',
  'architectural character',
  'distinctive character',
  'site-specific approach',
  'positioned as part of',
  'the court’s distinctive architecture',
  "the court's distinctive architecture",
  'foregrounds the site-specific use',
  'foregrounding its site-specific use',
  'drawing on her established practice',

  // General BAAD article-generation risk terms
  'cut tires',
  'knots and braids',
  'salvaged materials',
  'weathered surfaces',
  'shallower silhouettes',
  'hold likeness, memory, and presence',
  'holds likeness, memory, and presence',
  'everyday materials to hold likeness',
  'raw baad urls',
];

const mechanicalAttributionPhrases = [
  'the gallery notes',
  'the exhibition text frames',
  'the accompanying statement says',
  'the press release states',
  'the gallery says',
  'the statement notes',
  'according to the gallery',
  'a gallery statement highlights',
  'a gallery statement says',
  'the statement highlights',
  'the exhibition statement highlights',
  'the gallery statement',
];

const allowedStyleTerms = [
  'material',
  'surface',
  'light',
  'space',
  'architecture',
  'gesture',
  'form',
  'structure',
  'composition',
  'installation',
  'pattern',
  'colour',
  'color',
  'scale',
  'sculpture',
  'sound',
  'performance',
];

// -----------------------------------------------------------------------------
// 6) Detect phrase categories
// -----------------------------------------------------------------------------

const hardBanHits = hitObjects(
  findHits(hardBanPhrases, draftTextLower),
  draftText
);

const riskyHitsAll = hitObjects(
  findHits(riskyPhrases, draftTextLower),
  draftText
);

const subtleHitsAll = hitObjects(
  findHits(subtleUnsupportedPhrases, draftTextLower),
  draftText
).map((hit) => ({
  ...hit,
  reason:
    'Subtle unsupported interpretive, material, spatial, or process phrase. Source/context may be too thin to support this wording.',
}));

const mechanicalAttributionHits = hitObjects(
  findHits(mechanicalAttributionPhrases, draftTextLower),
  draftText
).map((hit) => ({
  ...hit,
  reason:
    'Mechanical attribution phrase. Rewrite into smoother BAAD prose unless direct attribution is editorially necessary.',
}));

const allowedStyleHits = hitObjects(
  findHits(allowedStyleTerms, draftTextLower),
  draftText
);

const unsupportedRiskyHits = riskyHitsAll.filter((hit) => {
  if (hit.appearsInSource) return false;

  if (sourceStrength === 'thin') return true;

  if (
    sourceStrength === 'moderate' &&
    [
      'transforms',
      'immersive',
      'atmosphere',
      'atmospheric',
      'resonant',
      'charged',
      'meditative',
      'monumental',
      'encounter',
      'in conversation with',
      'directly in conversation',
      'carries memory',
      'carry memory',
      'spatial composition',
      'sensory means',
      'sound structures',
      'architecture frame',
      'shaped for the site',
      'sets up a place',
      'sculptural presence',
    ].includes(hit.phrase)
  ) {
    return true;
  }

  return false;
});

const riskyButSourceSupportedHits = riskyHitsAll.filter((hit) => {
  return hit.appearsInSource;
});

const subtleUnsupportedHits = subtleHitsAll.filter((hit) => {
  if (hit.appearsInSource) return false;

  const alwaysRepair = [
    'cut tires',
    'knots and braids',
    'salvaged materials',
    'weathered surfaces',
    'shallower silhouettes',
    'hold likeness, memory, and presence',
    'holds likeness, memory, and presence',
    'everyday materials to hold likeness',
    'raw baad urls',
  ];

  if (alwaysRepair.includes(hit.phrase)) return true;

  if (sourceStrength === 'thin') return true;

  if (
    sourceStrength === 'moderate' &&
    [
      'each element positioned',
      'elements positioned',
      'unified site-specific approach',
      'constellation of components',
      'sonic and sculptural language',
      'sculptural language',
      'sonic language',
      'threading cultural memory',
      'lived experience into the installation',
      'spatial prompt',
      'court’s character',
      "court's character",
    ].includes(hit.phrase)
  ) {
    return true;
  }

  return false;
});

const subtleButSourceSupportedHits = subtleHitsAll.filter((hit) => {
  return hit.appearsInSource;
});

// -----------------------------------------------------------------------------
// 7) Dynamic required fact checks
// -----------------------------------------------------------------------------

const requiredFacts = [];

addRequiredFact(
  requiredFacts,
  'artist / subject name',
  sourceAnalysis.artistSubjectNames
);

addRequiredFact(
  requiredFacts,
  'project / exhibition title',
  sourceAnalysis.exhibitionProjectNames || closingInfo.projectExhibitionTitle
);

addRequiredFact(
  requiredFacts,
  'venue / institution',
  sourceAnalysis.venueInstitutionNames || closingInfo.venueInstitution
);

addRequiredFact(
  requiredFacts,
  'city / location',
  closingInfo.cityLocation
);

addRequiredFact(
  requiredFacts,
  'date / duration text',
  closingInfo.durationDateText
);

const mustPreserveParts = splitMustPreserve(sourceAnalysis.mustPreserve);

for (const part of mustPreserveParts) {
  const cleaned = cleanString(part);
  const lower = cleaned.toLowerCase();

  if (!cleaned) continue;

  if (cleaned.length > 90) continue;

  if (lower.includes('if verified')) continue;

  requiredFacts.push(makeRequiredFactFromMustPreserve(cleaned));
}

const draftTextNormalised = normaliseForMatch(draftText);

const missingRequiredFacts = requiredFacts.filter((fact) => {
  return !factIsPresent(fact, draftTextNormalised);
});

// -----------------------------------------------------------------------------
// 8) Closing paragraph safety checks
// -----------------------------------------------------------------------------

const closingIssues = [];

const hasNoVerifiedLinks =
  !closingInfo.baadExhibitionUrl &&
  !closingInfo.baadArtistUrl &&
  !closingInfo.baadGalleryUrl &&
  !closingInfo.artistWebsite &&
  !closingInfo.artistInstagram &&
  !closingInfo.galleryPage &&
  !closingInfo.museumInstitutionPage &&
  !closingInfo.otherRelevantLink;

if (closingInfo.useInDraft === true && hasNoVerifiedLinks) {
  const closingRiskTerms = [
    'learn more',
    'read more',
    'visit ',
    'follow ',
    'instagram',
    'website',
    'tickets',
    'book now',
    'http://',
    'https://',
  ];

  const closingRiskHits = closingRiskTerms.filter((phrase) =>
    draftTextLower.includes(phrase)
  );

  if (closingRiskHits.length > 0) {
    closingIssues.push({
      issue: 'Closing paragraph implies links/actions that are not verified.',
      hits: closingRiskHits,
    });
  }
}

const rawUrlHits = ['http://', 'https://'].filter((phrase) =>
  baadBodyLower.includes(phrase)
);

if (rawUrlHits.length > 0) {
  closingIssues.push({
    issue: 'Article body contains raw URL(s). Use a clean BAAD closing sentence instead of visible URLs.',
    hits: rawUrlHits,
  });
}

// -----------------------------------------------------------------------------
// 9) Decide pass / repair / human review
// -----------------------------------------------------------------------------

const reasons = [];

if (hardBanHits.length > 0) {
  reasons.push(`Hard-ban phrase(s) found: ${hardBanHits.map(h => h.phrase).join(', ')}`);
}

if (unsupportedRiskyHits.length > 0) {
  reasons.push(
    `Unsupported risky phrase(s) found for ${sourceStrength} source: ` +
    unsupportedRiskyHits.map(h => h.phrase).join(', ')
  );
}

if (subtleUnsupportedHits.length > 0) {
  reasons.push(
    `Subtle unsupported phrase(s) found for ${sourceStrength} source: ` +
    subtleUnsupportedHits.map(h => h.phrase).join(', ')
  );
}

if (mechanicalAttributionHits.length > 0) {
  reasons.push(
    `Mechanical attribution phrase(s) found: ` +
    mechanicalAttributionHits.map(h => h.phrase).join(', ')
  );
}

if (missingRequiredFacts.length > 0) {
  reasons.push(
    `Missing required fact(s): ${missingRequiredFacts.map(f => f.label).join(', ')}`
  );
}

if (closingIssues.length > 0) {
  reasons.push(
    `Closing issue(s): ${closingIssues.map(i => i.issue).join('; ')}`
  );
}

const draftPassesValidation =
  hardBanHits.length === 0 &&
  unsupportedRiskyHits.length === 0 &&
  subtleUnsupportedHits.length === 0 &&
  mechanicalAttributionHits.length === 0 &&
  missingRequiredFacts.length === 0 &&
  closingIssues.length === 0;

const validationDecision = draftPassesValidation
  ? 'pass'
  : 'repair';

const validationMessage = draftPassesValidation
  ? 'Draft passed BAAD context-aware validation.'
  : `Draft should be repaired before Airtable update. ${reasons.join(' ')}`;

// -----------------------------------------------------------------------------
// 10) Return enriched draft payload
// -----------------------------------------------------------------------------

return {
  json: {
    ...draft,

    validation: {
      draftPassesValidation,
      validationDecision,
      validationMessage,

      sourceWordCount,
      sourceStrength,

      sourcePacketsApplied,
      sourcePacketsCount,

      hardBanHits,

      riskyPhraseHits: riskyHitsAll,
      unsupportedRiskyHits,
      riskyButSourceSupportedHits,

      subtlePhraseHits: subtleHitsAll,
      subtleUnsupportedHits,
      subtleButSourceSupportedHits,

      mechanicalAttributionHits,

      allowedStyleHits,

      requiredFacts,
      missingRequiredFacts,
      closingIssues,

      articleId: draft.id || promptJson.id || promptJson.articleId || promptContext.articleId || '',
      sourceAnalysisId: draft.sourceAnalysisId || sourceAnalysis.sourceAnalysisId || '',
      styleBlueprintName: draft.styleBlueprintName || styleBlueprint.blueprintName || '',
      styleBlueprintRecordId: draft.styleBlueprintRecordId || styleBlueprint.recordId || '',
      closingInfoApplied: draft.closingInfoApplied === true,
      closingInfoRecordId: draft.closingInfoRecordId || workflow.closingInfoRecordId || '',
    },

    draftPassesValidation,
    validationDecision,
    validationMessage,
  },
};

// Parse Repaired LLM JSON
// Takes the repaired OpenAI response and turns it back into BAAD draft fields,
// while preserving article ID and workflow metadata from the original validation item.

// 1) Get raw text from OpenAI repair node.
const raw =
  $json.output?.[0]?.content?.[0]?.text ??
  $json.text ??
  $json.message?.content ??
  '';

// 2) Strip markdown fences if they appear.
const cleaned = String(raw || '')
  .replace(/```json/i, '')
  .replace(/```/g, '')
  .trim();

let data;

try {
  data = JSON.parse(cleaned);
} catch (err) {
  throw new Error(
    'Failed to parse repaired LLM JSON: ' + err.message + '\nRaw text:\n' + cleaned
  );
}

// 3) Pull original validated item to preserve IDs and metadata.
const validationItems = $items('Validate Draft Against BAAD Standards');
const validationItem = validationItems[$itemIndex];

if (!validationItem) {
  throw new Error(
    `Could not find source item from "Validate Draft Against BAAD Standards" for itemIndex=${$itemIndex}. ` +
    `Available items: ${validationItems.length}`
  );
}

const original = validationItem.json || {};
const originalValidation = original.validation || {};

const recordId =
  original.id ||
  originalValidation.articleId ||
  '';

if (!recordId) {
  throw new Error('Could not determine Airtable Article record ID from validation output.');
}

// 4) Return repaired draft in same shape as Parse LLM JSON output.
return {
  json: {
    id: recordId,

    baad_title: data.baad_title || '',
    baad_dek: data.baad_dek || '',
    baad_editor_summary: data.baad_editor_summary || '',
    baad_meta_description: data.baad_meta_description || '',
    baad_seo_title: data.baad_seo_title || '',
    baad_tags: Array.isArray(data.baad_tags) ? data.baad_tags : [],
    baad_body: data.baad_body || '',

    sourceAnalysisApplied: original.sourceAnalysisApplied === true,
    styleBlueprintApplied: original.styleBlueprintApplied === true,
    styleBlueprintName: original.styleBlueprintName || '',
    styleBlueprintRecordId: original.styleBlueprintRecordId || '',
    sourceAnalysisId: original.sourceAnalysisId || '',

    closingInfoApplied: original.closingInfoApplied === true,
    closingInfoRecordId: original.closingInfoRecordId || '',

    finalBaadBlueprintUsed:
      original.finalBaadBlueprintUsed ||
      original.styleBlueprintRecordId ||
      originalValidation.styleBlueprintRecordId ||
      '',

    blueprintSelectionSource:
      original.blueprintSelectionSource ||
      originalValidation.blueprintSelectionSource ||
      '',

    blueprintSelectionNotes:
      original.blueprintSelectionNotes ||
      original.blueprintSelectionReason ||
      originalValidation.blueprintSelectionNotes ||
      '',

    recommendedBlueprintRecordId:
      original.recommendedBlueprintRecordId ||
      originalValidation.recommendedBlueprintRecordId ||
      '',

    repairedDraft: true,
    originalValidationMessage: original.validationMessage || '',
    originalUnsupportedRiskyHits: originalValidation.unsupportedRiskyHits || [],
  },
};

// Validate Repaired Draft Against BAAD Standards
// Context-aware validation v5. Source Packet-aware repaired-draft validation.
// Generic validator: no article-specific required-fact exceptions.
// This node checks the repaired BAAD draft after Parse Repaired LLM JSON
// and compares it against source strength, source context, style-risk terms,
// subtle unsupported interpretation, attribution style, closing paragraph rules,
// dynamic required facts from promptContext, and approved BAAD Source Packets.

// -----------------------------------------------------------------------------
// 1) Current parsed repaired draft
// -----------------------------------------------------------------------------

const draft = $json;

const draftText = [
  draft.baad_title || '',
  draft.baad_dek || '',
  draft.baad_editor_summary || '',
  draft.baad_meta_description || '',
  draft.baad_seo_title || '',
  Array.isArray(draft.baad_tags) ? draft.baad_tags.join(' ') : '',
  draft.baad_body || '',
].join('\n\n');

const draftTextLower = draftText.toLowerCase();
const baadBodyLower = String(draft.baad_body || '').toLowerCase();

// -----------------------------------------------------------------------------
// 2) Pull prompt/source context from Build Draft Prompt
// -----------------------------------------------------------------------------

const promptItems = $items('Build Draft Prompt');
const promptItem = promptItems[$itemIndex] || promptItems[0];

if (!promptItem) {
  throw new Error(
    `Could not find source item from "Build Draft Prompt". Available items: ${promptItems.length}`
  );
}

const promptJson = promptItem.json || {};
const promptContext = promptJson.promptContext || {};

const source = promptContext.source || {};
const sourceAnalysis = promptContext.sourceAnalysis || {};
const styleBlueprint = promptContext.styleBlueprint || {};
const closingInfo = promptContext.closingInfo || {};
const workflow = promptContext.workflow || {};
const sourcePacketsContext = promptContext.sourcePackets || {};

// -----------------------------------------------------------------------------
// 3) Helpers
// -----------------------------------------------------------------------------

function asText(value) {
  if (Array.isArray(value)) {
    return value
      .map(asText)
      .filter(Boolean)
      .join('\n\n');
  }

  if (value && typeof value === 'object') {
    return Object.values(value)
      .map(asText)
      .filter(Boolean)
      .join('\n\n');
  }

  if (value === null || value === undefined) return '';
  return String(value);
}

function normaliseSourceBlockForDedupe(value) {
  return String(value || '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function uniqueTextBlocks(blocks) {
  const seen = new Set();
  const out = [];

  for (const block of blocks) {
    const text = asText(block).trim();
    if (!text) continue;

    const key = normaliseSourceBlockForDedupe(text);

    if (!key) continue;
    if (seen.has(key)) continue;

    seen.add(key);
    out.push(text);
  }

  return out;
}

function wordCount(text) {
  return String(text || '')
    .replace(/<[^>]+>/g, ' ')
    .trim()
    .split(/\s+/)
    .filter(Boolean).length;
}

function includesPhrase(textLower, phrase) {
  return textLower.includes(String(phrase).toLowerCase());
}

function findHits(phrases, textLower) {
  return phrases.filter((phrase) => includesPhrase(textLower, phrase));
}

function makeSnippet(text, phrase) {
  const lower = String(text || '').toLowerCase();
  const idx = lower.indexOf(String(phrase).toLowerCase());

  if (idx === -1) return '';

  const start = Math.max(0, idx - 90);
  const end = Math.min(String(text).length, idx + phrase.length + 120);

  return String(text)
    .slice(start, end)
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanString(value) {
  return String(value || '').trim();
}

function normaliseFact(value) {
  return cleanString(value).toLowerCase();
}

function normaliseForMatch(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[’‘]/g, "'")
    .replace(/[“”]/g, '"')
    .replace(/\bu\.s\.\b/g, 'us')
    .replace(/\bu\.s\./g, 'us')
    .replace(/-/g, ' ')
    .replace(/[^\w\s']/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function addRequiredFact(requiredFacts, label, value) {
  if (!value) return;

  if (Array.isArray(value)) {
    const cleaned = value
      .map(v => normaliseFact(v))
      .filter(Boolean);

    if (cleaned.length) {
      requiredFacts.push({
        label,
        mode: 'any',
        acceptable: cleaned,
      });
    }

    return;
  }

  const str = normaliseFact(value);
  if (!str) return;

  requiredFacts.push({
    label,
    mode: 'any',
    acceptable: [str],
  });
}

function splitMustPreserve(value) {
  return String(value || '')
    .split(';')
    .map(s => s.trim())
    .filter(Boolean);
}

function singulariseToken(token) {
  const t = normaliseForMatch(token);

  if (t.endsWith('ies') && t.length > 4) {
    return t.slice(0, -3) + 'y';
  }

  if (t.endsWith('s') && t.length > 3) {
    return t.slice(0, -1);
  }

  return t;
}

function gerundVariants(token) {
  const t = normaliseForMatch(token);
  const variants = new Set([t]);

  if (t.endsWith('ing') && t.length > 5) {
    let root = t.slice(0, -3);

    if (root.length > 2 && root[root.length - 1] === root[root.length - 2]) {
      root = root.slice(0, -1);
    }

    variants.add(root);
    variants.add(`${root}s`);
    variants.add(`${root}ed`);
    variants.add(`${root}e`);
    variants.add(`${root}es`);
  }

  return Array.from(variants).filter(Boolean);
}

function basicVariants(value) {
  const base = normaliseForMatch(value);
  const variants = new Set();

  if (!base) return [];

  variants.add(base);
  variants.add(singulariseToken(base));

  for (const variant of gerundVariants(base)) {
    variants.add(variant);
  }

  return Array.from(variants).filter(Boolean);
}

function makeSlashFact(label, lower) {
  const parts = lower
    .split('/')
    .map(p => normaliseForMatch(p))
    .filter(Boolean);

  const acceptable = new Set();

  acceptable.add(normaliseForMatch(lower));
  acceptable.add(normaliseForMatch(lower.replace(/\//g, ' and ')));
  acceptable.add(normaliseForMatch(lower.replace(/\//g, ' or ')));

  for (const part of parts) {
    for (const variant of basicVariants(part)) {
      acceptable.add(variant);
    }
  }

  return {
    label,
    mode: 'any',
    acceptable: Array.from(acceptable).filter(Boolean),
  };
}

function makeAndFact(label, lower) {
  const parts = lower
    .split(/\s+and\s+/)
    .map(p => normaliseForMatch(p))
    .filter(Boolean);

  const groups = parts.map((part) => {
    const variants = new Set(basicVariants(part));

    const tokens = part.split(/\s+/).filter(Boolean);
    for (const token of tokens) {
      for (const variant of basicVariants(token)) {
        variants.add(variant);
      }
    }

    return Array.from(variants).filter(Boolean);
  });

  return {
    label,
    mode: 'allGroups',
    groups,
  };
}

function significantTokens(value) {
  const stopWords = new Set([
    'a',
    'an',
    'and',
    'are',
    'as',
    'at',
    'by',
    'for',
    'from',
    'in',
    'into',
    'is',
    'it',
    'of',
    'on',
    'or',
    'that',
    'the',
    'their',
    'these',
    'this',
    'to',
    'with',
    'work',
    'works',
    'evocative',
  ]);

  return normaliseForMatch(value)
    .split(/\s+/)
    .map(t => t.trim())
    .filter(t => t.length > 2 && !stopWords.has(t));
}

function makeThresholdFact(label, lower) {
  const tokens = significantTokens(lower);

  return {
    label,
    mode: 'threshold',
    tokens,
    minMatches: Math.max(2, Math.ceil(tokens.length * 0.6)),
  };
}

function makeRequiredFactFromMustPreserve(cleaned) {
  const lower = cleanString(cleaned).toLowerCase();
  const label = `must preserve: ${cleaned}`;

  if (lower.includes('/')) {
    return makeSlashFact(label, lower);
  }

  if (/\s+and\s+/.test(lower)) {
    return makeAndFact(label, lower);
  }

  if (lower.length > 35) {
    return makeThresholdFact(label, lower);
  }

  return {
    label,
    mode: 'any',
    acceptable: basicVariants(lower),
  };
}

function factIsPresent(fact, draftNormalised) {
  if (!fact) return true;

  if (fact.mode === 'allGroups') {
    return (fact.groups || []).every((group) =>
      group.some((phrase) => draftNormalised.includes(normaliseForMatch(phrase)))
    );
  }

  if (fact.mode === 'threshold') {
    const tokens = fact.tokens || [];
    const matches = tokens.filter((token) =>
      draftNormalised.includes(normaliseForMatch(token))
    );

    return matches.length >= (fact.minMatches || 1);
  }

  return (fact.acceptable || []).some((phrase) =>
    draftNormalised.includes(normaliseForMatch(phrase))
  );
}

// -----------------------------------------------------------------------------
// 4) Build approved source corpus for validation
// -----------------------------------------------------------------------------

const sourcePacketItems =
  Array.isArray(sourcePacketsContext.sourcePackets)
    ? sourcePacketsContext.sourcePackets
    : Array.isArray(draft.sourcePackets)
      ? draft.sourcePackets
      : [];

const sourcePacketVerifiedContext = sourcePacketItems
  .map((packet) => [
    packet.name || '',
    packet.sourceType || '',
    packet.sourcePublisher || '',
    packet.sourceTitle || '',
    packet.sourceUrl || '',
    packet.promptReadyExtract || '',
    packet.verifiedFacts || '',
    packet.quoteCandidates || '',
    packet.quoteUseNotes || '',
    packet.sourceMeaningToRecast || '',
    packet.editorialUseNotes || '',
  ].map(asText).filter(Boolean).join('\n\n'))
  .filter(Boolean)
  .join('\n\n--- SOURCE PACKET ---\n\n');

const sourceTextBlocks = uniqueTextBlocks([
  source.sourceTitle || '',
  source.sourceDek || '',
  source.sourceBody || '',
  source.notes || '',

  source.sourceOutlet || '',
  source.sourceUrl || '',
  source.category || '',
  source.subcategory || '',
  source.articleType || '',

  sourceAnalysis.sourceArticleSummary || '',
  sourceAnalysis.mustPreserve || '',
  sourceAnalysis.bestBaadAngle || '',
  sourceAnalysis.avoidOveremphasising || '',
  sourceAnalysis.exhibitionProjectNames || '',
  sourceAnalysis.venueInstitutionNames || '',
  sourceAnalysis.artistSubjectNames || '',
  sourceAnalysis.analysisJson || '',

  closingInfo.projectExhibitionTitle || '',
  closingInfo.venueInstitution || '',
  closingInfo.cityLocation || '',
  closingInfo.durationDateText || '',
  closingInfo.recentArtistActivity || '',
  closingInfo.recentCommissionPrizeBookFairExhibition || '',

  promptJson['Sources Combined (for LLM)'] || '',
  promptJson.articleFields?.['Sources Combined (for LLM)'] || '',
  promptJson.fullArticleFields?.['Sources Combined (for LLM)'] || '',

  promptJson['LLM Block (from Article Sources)'] || '',
  promptJson.articleFields?.['LLM Block (from Article Sources)'] || '',
  promptJson.fullArticleFields?.['LLM Block (from Article Sources)'] || '',

  draft['Sources Combined (for LLM)'] || '',
  draft.articleFields?.['Sources Combined (for LLM)'] || '',
  draft.fullArticleFields?.['Sources Combined (for LLM)'] || '',

  draft['LLM Block (from Article Sources)'] || '',
  draft.articleFields?.['LLM Block (from Article Sources)'] || '',
  draft.fullArticleFields?.['LLM Block (from Article Sources)'] || '',

  sourcePacketsContext.sourcePacketsForPrompt || '',
  draft.sourcePacketsForPrompt || '',
  sourcePacketVerifiedContext,
]);

const sourceText = sourceTextBlocks.join('\n\n');

const sourceTextLower = sourceText.toLowerCase();

const sourceWordCount = wordCount(sourceText);

const sourcePacketsApplied =
  sourcePacketsContext.sourcePacketsApplied === true ||
  draft.sourcePacketsApplied === true ||
  sourcePacketItems.length > 0;

const sourcePacketsCount =
  Number(sourcePacketsContext.sourcePacketsCount || draft.sourcePacketsCount || sourcePacketItems.length || 0);

const sourceStrength =
  sourceWordCount < 180 ? 'thin' :
  sourceWordCount < 350 ? 'moderate' :
  'strong';

function hitObjects(phrases, text) {
  return phrases.map((phrase) => ({
    phrase,
    snippet: makeSnippet(text, phrase),
    appearsInSource: includesPhrase(sourceTextLower, phrase),
  }));
}

// -----------------------------------------------------------------------------
// 5) Phrase lists
// -----------------------------------------------------------------------------

const hardBanPhrases = [
  'must-see',
  'not to be missed',
  'groundbreaking',
  'game-changing',
  'masterpiece',
  'iconic artist',
  'important artist',
  'powerful statement',
  'revolutionary',
];

const riskyPhrases = [
  'transforms',
  'immersive',
  'atmosphere',
  'atmospheric',
  'resonant',
  'charged',
  'meditative',
  'monumental',
  'encounter',
  'in conversation with',
  'directly in conversation',
  'carries memory',
  'carry memory',
  'spatial composition',
  'sensory means',
  'sound structures',
  'architecture frame',
  'shaped for the site',
  'sets up a place',
  'sculptural presence',
];

const subtleUnsupportedPhrases = [
  'take centre stage',
  'takes centre stage',
  'take center stage',
  'takes center stage',
  'distinctive architecture',
  'setting the tone',
  'sets the tone',
  'spatial prompt',
  'provides the spatial prompt',
  'works with directly',
  'court’s character',
  "court's character",
  'responding to the court’s character',
  "responding to the court's character",
  'each element positioned',
  'elements positioned',
  'unified site-specific approach',
  'constellation of components',
  'cultural memory',
  'lived experience into the installation',
  'sonic and sculptural language',
  'sculptural language',
  'sonic language',
  'threads cultural memory',
  'threading cultural memory',
  'placed within the architecture',
  'places these elements within',
  'spatial character',
  'architectural character',
  'distinctive character',
  'site-specific approach',
  'positioned as part of',
  'the court’s distinctive architecture',
  "the court's distinctive architecture",
  'foregrounds the site-specific use',
  'foregrounding its site-specific use',
  'drawing on her established practice',

  // General BAAD article-generation risk terms
  'cut tires',
  'knots and braids',
  'salvaged materials',
  'weathered surfaces',
  'shallower silhouettes',
  'hold likeness, memory, and presence',
  'holds likeness, memory, and presence',
  'everyday materials to hold likeness',
  'raw baad urls',
];

const mechanicalAttributionPhrases = [
  'the gallery notes',
  'the exhibition text frames',
  'the accompanying statement says',
  'the press release states',
  'the gallery says',
  'the statement notes',
  'according to the gallery',
  'a gallery statement highlights',
  'a gallery statement says',
  'the statement highlights',
  'the exhibition statement highlights',
  'the gallery statement',
];

const allowedStyleTerms = [
  'material',
  'surface',
  'light',
  'space',
  'architecture',
  'gesture',
  'form',
  'structure',
  'composition',
  'installation',
  'pattern',
  'colour',
  'color',
  'scale',
  'sculpture',
  'sound',
  'performance',
];

// -----------------------------------------------------------------------------
// 6) Detect phrase categories
// -----------------------------------------------------------------------------

const hardBanHits = hitObjects(
  findHits(hardBanPhrases, draftTextLower),
  draftText
);

const riskyHitsAll = hitObjects(
  findHits(riskyPhrases, draftTextLower),
  draftText
);

const subtleHitsAll = hitObjects(
  findHits(subtleUnsupportedPhrases, draftTextLower),
  draftText
).map((hit) => ({
  ...hit,
  reason:
    'Subtle unsupported interpretive, material, spatial, or process phrase. Source/context may be too thin to support this wording.',
}));

const mechanicalAttributionHits = hitObjects(
  findHits(mechanicalAttributionPhrases, draftTextLower),
  draftText
).map((hit) => ({
  ...hit,
  reason:
    'Mechanical attribution phrase. Rewrite into smoother BAAD prose unless direct attribution is editorially necessary.',
}));

const allowedStyleHits = hitObjects(
  findHits(allowedStyleTerms, draftTextLower),
  draftText
);

const unsupportedRiskyHits = riskyHitsAll.filter((hit) => {
  if (hit.appearsInSource) return false;

  if (sourceStrength === 'thin') return true;

  if (
    sourceStrength === 'moderate' &&
    [
      'transforms',
      'immersive',
      'atmosphere',
      'atmospheric',
      'resonant',
      'charged',
      'meditative',
      'monumental',
      'encounter',
      'in conversation with',
      'directly in conversation',
      'carries memory',
      'carry memory',
      'spatial composition',
      'sensory means',
      'sound structures',
      'architecture frame',
      'shaped for the site',
      'sets up a place',
      'sculptural presence',
    ].includes(hit.phrase)
  ) {
    return true;
  }

  return false;
});

const riskyButSourceSupportedHits = riskyHitsAll.filter((hit) => {
  return hit.appearsInSource;
});

const subtleUnsupportedHits = subtleHitsAll.filter((hit) => {
  if (hit.appearsInSource) return false;

  const alwaysRepair = [
    'cut tires',
    'knots and braids',
    'salvaged materials',
    'weathered surfaces',
    'shallower silhouettes',
    'hold likeness, memory, and presence',
    'holds likeness, memory, and presence',
    'everyday materials to hold likeness',
    'raw baad urls',
  ];

  if (alwaysRepair.includes(hit.phrase)) return true;

  if (sourceStrength === 'thin') return true;

  if (
    sourceStrength === 'moderate' &&
    [
      'each element positioned',
      'elements positioned',
      'unified site-specific approach',
      'constellation of components',
      'sonic and sculptural language',
      'sculptural language',
      'sonic language',
      'threading cultural memory',
      'lived experience into the installation',
      'spatial prompt',
      'court’s character',
      "court's character",
    ].includes(hit.phrase)
  ) {
    return true;
  }

  return false;
});

const subtleButSourceSupportedHits = subtleHitsAll.filter((hit) => {
  return hit.appearsInSource;
});

// -----------------------------------------------------------------------------
// 7) Dynamic required fact checks
// -----------------------------------------------------------------------------

const requiredFacts = [];

addRequiredFact(
  requiredFacts,
  'artist / subject name',
  sourceAnalysis.artistSubjectNames
);

addRequiredFact(
  requiredFacts,
  'project / exhibition title',
  sourceAnalysis.exhibitionProjectNames || closingInfo.projectExhibitionTitle
);

addRequiredFact(
  requiredFacts,
  'venue / institution',
  sourceAnalysis.venueInstitutionNames || closingInfo.venueInstitution
);

addRequiredFact(
  requiredFacts,
  'city / location',
  closingInfo.cityLocation
);

addRequiredFact(
  requiredFacts,
  'date / duration text',
  closingInfo.durationDateText
);

const mustPreserveParts = splitMustPreserve(sourceAnalysis.mustPreserve);

for (const part of mustPreserveParts) {
  const cleaned = cleanString(part);
  const lower = cleaned.toLowerCase();

  if (!cleaned) continue;

  if (cleaned.length > 90) continue;

  if (lower.includes('if verified')) continue;

  requiredFacts.push(makeRequiredFactFromMustPreserve(cleaned));
}

const draftTextNormalised = normaliseForMatch(draftText);

const missingRequiredFacts = requiredFacts.filter((fact) => {
  return !factIsPresent(fact, draftTextNormalised);
});

// -----------------------------------------------------------------------------
// 8) Closing paragraph safety checks
// -----------------------------------------------------------------------------

const closingIssues = [];

const hasNoVerifiedLinks =
  !closingInfo.baadExhibitionUrl &&
  !closingInfo.baadArtistUrl &&
  !closingInfo.baadGalleryUrl &&
  !closingInfo.artistWebsite &&
  !closingInfo.artistInstagram &&
  !closingInfo.galleryPage &&
  !closingInfo.museumInstitutionPage &&
  !closingInfo.otherRelevantLink;

if (closingInfo.useInDraft === true && hasNoVerifiedLinks) {
  const closingRiskTerms = [
    'learn more',
    'read more',
    'visit ',
    'follow ',
    'instagram',
    'website',
    'tickets',
    'book now',
    'http://',
    'https://',
  ];

  const closingRiskHits = closingRiskTerms.filter((phrase) =>
    draftTextLower.includes(phrase)
  );

  if (closingRiskHits.length > 0) {
    closingIssues.push({
      issue: 'Closing paragraph implies links/actions that are not verified.',
      hits: closingRiskHits,
    });
  }
}

const rawUrlHits = ['http://', 'https://'].filter((phrase) =>
  baadBodyLower.includes(phrase)
);

if (rawUrlHits.length > 0) {
  closingIssues.push({
    issue: 'Article body contains raw URL(s). Use a clean BAAD closing sentence instead of visible URLs.',
    hits: rawUrlHits,
  });
}

// -----------------------------------------------------------------------------
// 9) Decide pass / repair / human review
// -----------------------------------------------------------------------------

const reasons = [];

if (hardBanHits.length > 0) {
  reasons.push(`Hard-ban phrase(s) found: ${hardBanHits.map(h => h.phrase).join(', ')}`);
}

if (unsupportedRiskyHits.length > 0) {
  reasons.push(
    `Unsupported risky phrase(s) found for ${sourceStrength} source: ` +
    unsupportedRiskyHits.map(h => h.phrase).join(', ')
  );
}

if (subtleUnsupportedHits.length > 0) {
  reasons.push(
    `Subtle unsupported phrase(s) found for ${sourceStrength} source: ` +
    subtleUnsupportedHits.map(h => h.phrase).join(', ')
  );
}

if (mechanicalAttributionHits.length > 0) {
  reasons.push(
    `Mechanical attribution phrase(s) found: ` +
    mechanicalAttributionHits.map(h => h.phrase).join(', ')
  );
}

if (missingRequiredFacts.length > 0) {
  reasons.push(
    `Missing required fact(s): ${missingRequiredFacts.map(f => f.label).join(', ')}`
  );
}

if (closingIssues.length > 0) {
  reasons.push(
    `Closing issue(s): ${closingIssues.map(i => i.issue).join('; ')}`
  );
}

const draftPassesValidation =
  hardBanHits.length === 0 &&
  unsupportedRiskyHits.length === 0 &&
  subtleUnsupportedHits.length === 0 &&
  mechanicalAttributionHits.length === 0 &&
  missingRequiredFacts.length === 0 &&
  closingIssues.length === 0;

const validationDecision = draftPassesValidation
  ? 'pass'
  : 'repair';

const validationMessage = draftPassesValidation
  ? 'Draft passed BAAD context-aware validation.'
  : `Draft should be repaired before Airtable update. ${reasons.join(' ')}`;

// -----------------------------------------------------------------------------
// 10) Return enriched draft payload
// -----------------------------------------------------------------------------

return {
  json: {
    ...draft,

    validation: {
      draftPassesValidation,
      validationDecision,
      validationMessage,

      sourceWordCount,
      sourceStrength,

      sourcePacketsApplied,
      sourcePacketsCount,

      hardBanHits,

      riskyPhraseHits: riskyHitsAll,
      unsupportedRiskyHits,
      riskyButSourceSupportedHits,

      subtlePhraseHits: subtleHitsAll,
      subtleUnsupportedHits,
      subtleButSourceSupportedHits,

      mechanicalAttributionHits,

      allowedStyleHits,

      requiredFacts,
      missingRequiredFacts,
      closingIssues,

      articleId: draft.id || promptJson.id || promptJson.articleId || promptContext.articleId || '',
      sourceAnalysisId: draft.sourceAnalysisId || sourceAnalysis.sourceAnalysisId || '',
      styleBlueprintName: draft.styleBlueprintName || styleBlueprint.blueprintName || '',
      styleBlueprintRecordId: draft.styleBlueprintRecordId || styleBlueprint.recordId || '',
      closingInfoApplied: draft.closingInfoApplied === true,
      closingInfoRecordId: draft.closingInfoRecordId || workflow.closingInfoRecordId || '',
    },

    draftPassesValidation,
    validationDecision,
    validationMessage,
  },
};

// Final Clean Draft Fields
// Small final cleanup before Airtable update.
// This is not a rewrite step.
// It only prepares a compact, safe payload for the Airtable update node.
//
// Important:
// Do NOT spread the full item here, because that carries promptContext,
// sourcePackets, validation debug data, and full source packet text into
// the final Airtable update path.

const item = $json;
const validation = item.validation || {};

let baadTitle = item.baad_title || '';

// General cleanup: avoid interpretive title verbs if they appear,
// especially after repair on thin sources.
baadTitle = baadTitle
  .replace(/\bgrounds\b/i, 'presents')
  .replace(/\btransforms\b/i, 'presents')
  .replace(/\breimagines\b/i, 'presents')
  .replace(/\bpositions\b/i, 'presents')
  .replace(/\bsituates\b/i, 'presents')
  .trim();

const baadTags = Array.isArray(item.baad_tags)
  ? item.baad_tags
  : String(item.baad_tags || '')
      .split(',')
      .map((tag) => tag.trim())
      .filter(Boolean);

return {
  json: {
    // Airtable record ID
    id: item.id || validation.articleId || '',

    // Final BAAD draft fields
    baad_title: baadTitle,
    baad_dek: item.baad_dek || '',
    baad_editor_summary: item.baad_editor_summary || '',
    baad_meta_description: item.baad_meta_description || '',
    baad_seo_title: item.baad_seo_title || '',
    baad_tags: baadTags,
    baad_body: item.baad_body || '',

    // Workflow/validation status
    draftPassesValidation: item.draftPassesValidation === true || validation.draftPassesValidation === true,
    validationDecision: item.validationDecision || validation.validationDecision || '',
    validationMessage: item.validationMessage || validation.validationMessage || '',

    // Source-analysis / blueprint / closing metadata
    sourceAnalysisApplied: item.sourceAnalysisApplied === true,
    sourceAnalysisId: item.sourceAnalysisId || validation.sourceAnalysisId || '',

    styleBlueprintApplied: item.styleBlueprintApplied === true,
    styleBlueprintName: item.styleBlueprintName || validation.styleBlueprintName || '',
    styleBlueprintRecordId: item.styleBlueprintRecordId || validation.styleBlueprintRecordId || '',

    finalBaadBlueprintUsed:
      item.finalBaadBlueprintUsed ||
      item.styleBlueprintRecordId ||
      validation.styleBlueprintRecordId ||
      '',

    blueprintSelectionSource:
      item.blueprintSelectionSource ||
      validation.blueprintSelectionSource ||
      '',

    blueprintSelectionNotes:
      item.blueprintSelectionNotes ||
      item.blueprintSelectionReason ||
      validation.blueprintSelectionNotes ||
      '',

    recommendedBlueprintRecordId:
      item.recommendedBlueprintRecordId ||
      validation.recommendedBlueprintRecordId ||
      '',

    closingInfoApplied: item.closingInfoApplied === true || validation.closingInfoApplied === true,
    closingInfoRecordId: item.closingInfoRecordId || validation.closingInfoRecordId || '',

    // Source Packet audit fields
    sourcePacketsApplied: item.sourcePacketsApplied === true || validation.sourcePacketsApplied === true,
    sourcePacketsCount: Number(item.sourcePacketsCount || validation.sourcePacketsCount || 0),

    // Polish metadata
    polishApplied: item.polishApplied === true,
    polish_notes: item.polish_notes || '',

    // Optional QA notes, useful if you map them to Airtable later
    unsupported_additions_check: item.unsupported_additions_check || '',
    facts_preserved_checklist: Array.isArray(item.facts_preserved_checklist)
      ? item.facts_preserved_checklist
      : [],

    // Clear stale error fields after successful final draft update.
    // These are mapped in the Airtable update node.
    lastErrorClear: '',
    lastErrorStepClear: '',
  },
};

// Parse Polished Draft JSON
// Takes the polished OpenAI response and turns it back into BAAD draft fields,
// while preserving article ID, source/blueprint/closing metadata, previous validation,
// full prompt context, and polish metadata.
//
// This version supports BOTH routes:
// 1) First validation passed  → skipped repair → Build Polish Prompt → Polish BAAD Draft
// 2) First validation failed → repair → repaired validation → Build Polish Prompt → Polish BAAD Draft

// -----------------------------------------------------------------------------
// 1) Get raw text from OpenAI polish node.
// -----------------------------------------------------------------------------

const raw =
  $json.output?.[0]?.content?.[0]?.text ??
  $json.text ??
  $json.message?.content ??
  $json.choices?.[0]?.message?.content ??
  $json.content ??
  '';

const cleaned = String(raw || '')
  .replace(/```json/i, '')
  .replace(/```/g, '')
  .trim();

let data;

try {
  data = JSON.parse(cleaned);
} catch (err) {
  throw new Error(
    'Failed to parse polished LLM JSON: ' + err.message + '\nRaw text:\n' + cleaned
  );
}

// -----------------------------------------------------------------------------
// 2) Safely read previous node items.
// -----------------------------------------------------------------------------
// Important: after adding IF Draft Needs Repair?, the repaired validation node
// may not execute. Calling $items() on a node that did not execute can throw.
// This helper prevents that.

function safeItems(nodeName) {
  try {
    return $items(nodeName) || [];
  } catch (err) {
    return [];
  }
}

function pickItem(items) {
  return items[$itemIndex] || items[0] || null;
}

const buildPolishPromptItem = pickItem(safeItems('Build Polish Prompt'));
const repairedValidationItem = pickItem(safeItems('Validate Repaired Draft Against BAAD Standards'));
const firstValidationItem = pickItem(safeItems('Validate Draft Against BAAD Standards'));
const buildDraftPromptItem = pickItem(safeItems('Build Draft Prompt'));

const buildPolishPromptJson = buildPolishPromptItem?.json || {};
const repairedValidationJson = repairedValidationItem?.json || {};
const firstValidationJson = firstValidationItem?.json || {};
const buildDraftPromptJson = buildDraftPromptItem?.json || {};

// -----------------------------------------------------------------------------
// 3) Choose the best original/context source.
// -----------------------------------------------------------------------------
// Build Polish Prompt is preferred because it runs in both routes.
// Repaired validation is only available when repair happened.
// First validation is available when the original draft passed.

const original =
  buildPolishPromptJson.id
    ? buildPolishPromptJson
    : repairedValidationJson.id
      ? repairedValidationJson
      : firstValidationJson.id
        ? firstValidationJson
        : buildDraftPromptJson;

const originalValidation =
  original.validation ||
  repairedValidationJson.validation ||
  firstValidationJson.validation ||
  {};

// Full prompt context can be carried by Build Polish Prompt or Build Draft Prompt.
const fullPromptContext =
  original.promptContext ||
  buildPolishPromptJson.promptContext ||
  repairedValidationJson.promptContext ||
  firstValidationJson.promptContext ||
  buildDraftPromptJson.promptContext ||
  buildDraftPromptJson ||
  {};

// -----------------------------------------------------------------------------
// 4) Determine Airtable Article record ID.
// -----------------------------------------------------------------------------

const recordId =
  original.id ||
  originalValidation.articleId ||
  fullPromptContext.articleId ||
  fullPromptContext.id ||
  buildDraftPromptJson.id ||
  '';

if (!recordId) {
  throw new Error(
    'Could not determine Airtable Article record ID from Build Polish Prompt, validation output, or prompt context.'
  );
}

// -----------------------------------------------------------------------------
// 5) Normalize metadata.
// -----------------------------------------------------------------------------

const styleBlueprintName =
  original.styleBlueprintName ||
  originalValidation.styleBlueprintName ||
  fullPromptContext.styleBlueprintName ||
  fullPromptContext.styleBlueprint?.blueprintName ||
  '';

const styleBlueprintRecordId =
  original.styleBlueprintRecordId ||
  originalValidation.styleBlueprintRecordId ||
  fullPromptContext.styleBlueprintRecordId ||
  fullPromptContext.styleBlueprint?.recordId ||
  '';

const sourceAnalysisId =
  original.sourceAnalysisId ||
  originalValidation.sourceAnalysisId ||
  fullPromptContext.sourceAnalysisId ||
  fullPromptContext.sourceAnalysis?.sourceAnalysisId ||
  '';

const closingInfoApplied =
  original.closingInfoApplied === true ||
  originalValidation.closingInfoApplied === true ||
  fullPromptContext.closingInfoApplied === true ||
  fullPromptContext.closingInfo?.useInDraft === true ||
  false;

const closingInfoRecordId =
  original.closingInfoRecordId ||
  originalValidation.closingInfoRecordId ||
  fullPromptContext.closingInfoRecordId ||
  fullPromptContext.closingInfo?.closingInfoId ||
  '';

const sourcePacketsApplied =
  original.sourcePacketsApplied === true ||
  fullPromptContext.sourcePackets?.sourcePacketsApplied === true ||
  false;

const sourcePacketsCount =
  Number(
    original.sourcePacketsCount ||
    fullPromptContext.sourcePackets?.sourcePacketsCount ||
    0
  );

// -----------------------------------------------------------------------------
// 6) Return polished draft in the same shape expected by validator/final update.
// -----------------------------------------------------------------------------

return {
  json: {
    id: recordId,

    baad_title: data.baad_title || '',
    baad_dek: data.baad_dek || '',
    baad_editor_summary: data.baad_editor_summary || '',
    baad_meta_description: data.baad_meta_description || '',
    baad_seo_title: data.baad_seo_title || '',
    baad_tags: Array.isArray(data.baad_tags) ? data.baad_tags : [],
    baad_body: data.baad_body || '',

    sourceAnalysisApplied:
      original.sourceAnalysisApplied === true ||
      Boolean(sourceAnalysisId),

    styleBlueprintApplied:
      original.styleBlueprintApplied === true ||
      Boolean(styleBlueprintRecordId),

    styleBlueprintName,
    styleBlueprintRecordId,
    sourceAnalysisId,

    closingInfoApplied,
    closingInfoRecordId,

    sourcePacketsApplied,

    finalBaadBlueprintUsed:
      original.finalBaadBlueprintUsed ||
      original.styleBlueprintRecordId ||
      originalValidation.styleBlueprintRecordId ||
      '',

    blueprintSelectionSource:
      original.blueprintSelectionSource ||
      originalValidation.blueprintSelectionSource ||
      '',

    blueprintSelectionNotes:
      original.blueprintSelectionNotes ||
      original.blueprintSelectionReason ||
      originalValidation.blueprintSelectionNotes ||
      '',

    recommendedBlueprintRecordId:
      original.recommendedBlueprintRecordId ||
      originalValidation.recommendedBlueprintRecordId ||
      '',
    sourcePacketsCount,

    promptContext: fullPromptContext,
    previousValidation: originalValidation,

    polishApplied: true,
    polish_notes: data.polish_notes || '',
    facts_preserved_checklist: Array.isArray(data.facts_preserved_checklist)
      ? data.facts_preserved_checklist
      : [],
    unsupported_additions_check: data.unsupported_additions_check || '',
  },
};

// Validate Polished Draft Against BAAD Standards
// Context-aware validation v5.
// Generic validator: no article-specific required-fact exceptions.
// This node checks the polished BAAD draft after Parse Polished Draft JSON.
//
// Supports the new routing:
// 1) first draft passes → repair skipped → polish → validate polished draft
// 2) first draft fails → repair → repaired validation → polish → validate polished draft
//
// Main fix in this version:
// - Reads Source Packet context from draft.promptContext.sourcePackets
// - Falls back to previousValidation where useful
// - Avoids treating source-supported phrases like "immersive" as unsupported

const draft = $json;

const draftText = [
  draft.baad_title || '',
  draft.baad_dek || '',
  draft.baad_editor_summary || '',
  draft.baad_meta_description || '',
  draft.baad_seo_title || '',
  Array.isArray(draft.baad_tags) ? draft.baad_tags.join(' ') : '',
  draft.baad_body || '',
].join('\n\n');

const draftTextLower = draftText.toLowerCase();
const baadBodyLower = String(draft.baad_body || '').toLowerCase();

// -----------------------------------------------------------------------------
// 1) Safe helpers for optional node lookups
// -----------------------------------------------------------------------------

function safeItems(nodeName) {
  try {
    return $items(nodeName) || [];
  } catch (err) {
    return [];
  }
}

function pickItem(items) {
  return items[$itemIndex] || items[0] || null;
}

function asText(value) {
  if (Array.isArray(value)) {
    return value
      .map((item) => asText(item))
      .filter(Boolean)
      .join('\n\n');
  }

  if (value && typeof value === 'object') {
    return Object.entries(value)
      .map(([key, val]) => `${key}: ${asText(val)}`)
      .filter(Boolean)
      .join('\n');
  }

  if (value === null || value === undefined) return '';
  return String(value);
}

// -----------------------------------------------------------------------------
// 2) Pull prompt/source context
// -----------------------------------------------------------------------------
// Prefer the promptContext already carried by Parse Polished Draft JSON.
// Fall back to Build Polish Prompt / Build Draft Prompt only if needed.

