    packet.editorialUseNotes || '',
  ].map(asText).filter(Boolean).join('\n\n'))
  .filter(Boolean)
  .join('\n\n--- SOURCE PACKET ---\n\n');

const sourceText = [
  source.sourceTitle || '',
  source.sourceDek || '',
  source.sourceBody || '',
