  closingInfo.recentArtistActivity || '',
  closingInfo.recentCommissionPrizeBookFairExhibition || '',

  sourcePacketsContext.sourcePacketsForPrompt || '',
  sourcePacketVerifiedContext,

  previousValidation.sourcePacketsApplied === true ? 'source packets previously applied' : '',
].map(asText).filter(Boolean).join('\n\n');

const sourceTextLower = sourceText.toLowerCase();

function wordCount(text) {
  return String(text || '')
    .trim()
    .split(/\s+/)
    .filter(Boolean).length;
}

const sourceWordCount = wordCount(sourceText);

const sourceStrength =
  sourceWordCount < 180 ? 'thin' :
  sourceWordCount < 350 ? 'moderate' :
