// -----------------------------------------------------------------------------
// 4) Helpers
// -----------------------------------------------------------------------------

function includesPhrase(textLower, phrase) {
  return textLower.includes(String(phrase).toLowerCase());
}

function findHits(phrases, textLower) {
  return phrases.filter((phrase) => includesPhrase(textLower, phrase));
}

function makeSnippet(text, phrase) {
  const lower = String(text || '').toLowerCase();
  const idx = lower.indexOf(String(phrase).toLowerCase());

  if (idx === -1) return '';

  const start = Math.max(0, idx - 90);
  const end = Math.min(String(text).length, idx + phrase.length + 120);

  return String(text)
    .slice(start, end)
    .replace(/\s+/g, ' ')
    .trim();
}

function hitObjects(phrases, text) {
  return phrases.map((phrase) => ({
    phrase,
    snippet: makeSnippet(text, phrase),
    appearsInSource: includesPhrase(sourceTextLower, phrase),
  }));
}

function cleanString(value) {
  return String(value || '').trim();
}

function normaliseFact(value) {
  return cleanString(value).toLowerCase();
}

function addRequiredFact(requiredFacts, label, value) {
  if (!value) return;

  if (Array.isArray(value)) {
    const cleaned = value
      .map(v => normaliseFact(v))
      .filter(Boolean);

    if (cleaned.length) {
      requiredFacts.push({
        label,
        mode: 'any',
        acceptable: cleaned,
      });
    }

    return;
  }

  const str = normaliseFact(value);
  if (!str) return;

  requiredFacts.push({
    label,
    mode: 'any',
    acceptable: [str],
  });
}

function splitMustPreserve(value) {
  return String(value || '')
    .split(';')
    .map(s => s.trim())
    .filter(Boolean);
}

function normaliseForMatch(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[’‘]/g, "'")
    .replace(/[“”]/g, '"')
    .replace(/\bu\.s\.\b/g, 'us')
    .replace(/\bu\.s\./g, 'us')
    .replace(/-/g, ' ')
    .replace(/[^\w\s']/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function singulariseToken(token) {
  const t = normaliseForMatch(token);

  if (t.endsWith('ies') && t.length > 4) {
    return t.slice(0, -3) + 'y';
  }

  if (t.endsWith('s') && t.length > 3) {
    return t.slice(0, -1);
  }

  return t;
}

function gerundVariants(token) {
  const t = normaliseForMatch(token);
  const variants = new Set([t]);

  if (t.endsWith('ing') && t.length > 5) {
    let root = t.slice(0, -3);

    if (root.length > 2 && root[root.length - 1] === root[root.length - 2]) {
      root = root.slice(0, -1);
    }

    variants.add(root);
    variants.add(`${root}s`);
    variants.add(`${root}ed`);
    variants.add(`${root}e`);
    variants.add(`${root}es`);
  }

  return Array.from(variants).filter(Boolean);
}

function basicVariants(value) {
  const base = normaliseForMatch(value);
  const variants = new Set();

  if (!base) return [];

  variants.add(base);
  variants.add(singulariseToken(base));

  for (const variant of gerundVariants(base)) {
    variants.add(variant);
  }

  return Array.from(variants).filter(Boolean);
}

function makeSlashFact(label, lower) {
  const parts = lower
    .split('/')
    .map(p => normaliseForMatch(p))
    .filter(Boolean);

  const acceptable = new Set();

  acceptable.add(normaliseForMatch(lower));
  acceptable.add(normaliseForMatch(lower.replace(/\//g, ' and ')));
  acceptable.add(normaliseForMatch(lower.replace(/\//g, ' or ')));

  for (const part of parts) {
    for (const variant of basicVariants(part)) {
      acceptable.add(variant);
    }
  }

  return {
    label,
    mode: 'any',
    acceptable: Array.from(acceptable).filter(Boolean),
  };
}

function makeAndFact(label, lower) {
  const parts = lower
    .split(/\s+and\s+/)
    .map(p => normaliseForMatch(p))
    .filter(Boolean);

  const groups = parts.map((part) => {
    const variants = new Set(basicVariants(part));

    const tokens = part.split(/\s+/).filter(Boolean);
    for (const token of tokens) {
      for (const variant of basicVariants(token)) {
        variants.add(variant);
      }
    }

    return Array.from(variants).filter(Boolean);
  });

  return {
    label,
    mode: 'allGroups',
    groups,
  };
}

function significantTokens(value) {
  const stopWords = new Set([
    'a',
    'an',
    'and',
    'are',
    'as',
    'at',
    'by',
    'for',
    'from',
    'in',
    'into',
    'is',
    'it',
    'of',
    'on',
    'or',
    'that',
    'the',
    'their',
    'these',
    'this',
    'to',
    'with',
    'work',
    'works',
    'evocative',
  ]);

  return normaliseForMatch(value)
    .split(/\s+/)
    .map(t => t.trim())
    .filter(t => t.length > 2 && !stopWords.has(t));
}

function makeThresholdFact(label, lower) {
  const tokens = significantTokens(lower);

  return {
    label,
    mode: 'threshold',
    tokens,
    minMatches: Math.max(2, Math.ceil(tokens.length * 0.6)),
  };
}

function makeRequiredFactFromMustPreserve(cleaned) {
  const lower = cleanString(cleaned).toLowerCase();
  const label = `must preserve: ${cleaned}`;

  if (lower.includes('/')) {
    return makeSlashFact(label, lower);
  }

  if (/\s+and\s+/.test(lower)) {
    return makeAndFact(label, lower);
  }

  if (lower.length > 35) {
    return makeThresholdFact(label, lower);
  }

  return {
    label,
    mode: 'any',
    acceptable: basicVariants(lower),
  };
}

function factIsPresent(fact, draftNormalised) {
  if (!fact) return true;

  if (fact.mode === 'allGroups') {
    return (fact.groups || []).every((group) =>
      group.some((phrase) => draftNormalised.includes(normaliseForMatch(phrase)))
    );
  }

  if (fact.mode === 'threshold') {
    const tokens = fact.tokens || [];
    const matches = tokens.filter((token) =>
      draftNormalised.includes(normaliseForMatch(token))
    );

    return matches.length >= (fact.minMatches || 1);
  }

  return (fact.acceptable || []).some((phrase) =>
    draftNormalised.includes(normaliseForMatch(phrase))
  );
}

// -----------------------------------------------------------------------------
// 5) Detect phrase categories
// -----------------------------------------------------------------------------

const hardBanHits = hitObjects(
  findHits(hardBanPhrases, draftTextLower),
  draftText
);

const riskyHitsAll = hitObjects(
  findHits(riskyPhrases, draftTextLower),
  draftText
);

const subtleHitsAll = hitObjects(
  findHits(subtleUnsupportedPhrases, draftTextLower),
  draftText
).map((hit) => ({
  ...hit,
  reason:
    'Subtle unsupported interpretive, material, spatial, or process phrase. Source/context may be too thin to support this wording.',
}));

const mechanicalAttributionHits = hitObjects(
  findHits(mechanicalAttributionPhrases, draftTextLower),
  draftText
).map((hit) => ({
  ...hit,
  reason:
    'Mechanical attribution phrase. Rewrite into smoother BAAD prose unless direct attribution is editorially necessary.',
}));

const allowedStyleHits = hitObjects(
  findHits(allowedStyleTerms, draftTextLower),
  draftText
);

const unsupportedRiskyHits = riskyHitsAll.filter((hit) => {
  if (hit.appearsInSource) return false;

  if (sourceStrength === 'thin') return true;

  if (
    sourceStrength === 'moderate' &&
    [
      'transforms',
      'immersive',
      'atmosphere',
      'atmospheric',
      'resonant',
      'charged',
      'meditative',
      'monumental',
      'encounter',
      'in conversation with',
      'directly in conversation',
      'carries memory',
      'carry memory',
      'spatial composition',
      'sensory means',
      'sound structures',
      'architecture frame',
      'shaped for the site',
      'sets up a place',
      'sculptural presence',
    ].includes(hit.phrase)
  ) {
    return true;
  }

  return false;
});

const riskyButSourceSupportedHits = riskyHitsAll.filter((hit) => {
  return hit.appearsInSource;
});

const subtleUnsupportedHits = subtleHitsAll.filter((hit) => {
  if (hit.appearsInSource) return false;

  const alwaysRepair = [
    'cut tires',
    'knots and braids',
    'salvaged materials',
    'weathered surfaces',
    'shallower silhouettes',
    'hold likeness, memory, and presence',
    'holds likeness, memory, and presence',
    'everyday materials to hold likeness',
    'raw baad urls',
  ];

  if (alwaysRepair.includes(hit.phrase)) return true;

  if (sourceStrength === 'thin') return true;

  if (
    sourceStrength === 'moderate' &&
    [
      'each element positioned',
      'elements positioned',
      'unified site-specific approach',
      'constellation of components',
      'sonic and sculptural language',
      'sculptural language',
      'sonic language',
      'threading cultural memory',
      'lived experience into the installation',
      'spatial prompt',
      'court’s character',
      "court's character",
    ].includes(hit.phrase)
  ) {
    return true;
  }

  return false;
});

const subtleButSourceSupportedHits = subtleHitsAll.filter((hit) => {
  return hit.appearsInSource;
});

// -----------------------------------------------------------------------------
// 6) Dynamic required fact checks
// -----------------------------------------------------------------------------

const requiredFacts = [];

addRequiredFact(
  requiredFacts,
  'artist / subject name',
  sourceAnalysis.artistSubjectNames
);

addRequiredFact(
  requiredFacts,
  'project / exhibition title',
  sourceAnalysis.exhibitionProjectNames || closingInfo.projectExhibitionTitle
);

addRequiredFact(
  requiredFacts,
  'venue / institution',
  sourceAnalysis.venueInstitutionNames || closingInfo.venueInstitution
);

addRequiredFact(
  requiredFacts,
  'city / location',
  closingInfo.cityLocation
);

addRequiredFact(
  requiredFacts,
  'date / duration text',
  closingInfo.durationDateText
);

const mustPreserveParts = splitMustPreserve(sourceAnalysis.mustPreserve);

for (const part of mustPreserveParts) {
  const cleaned = cleanString(part);
  const lower = cleaned.toLowerCase();

  if (!cleaned) continue;

  if (cleaned.length > 90) continue;

  if (lower.includes('if verified')) continue;

  requiredFacts.push(makeRequiredFactFromMustPreserve(cleaned));
}

const draftTextNormalised = normaliseForMatch(draftText);

const missingRequiredFacts = requiredFacts.filter((fact) => {
  return !factIsPresent(fact, draftTextNormalised);
});

// -----------------------------------------------------------------------------
// 7) Closing paragraph safety checks
// -----------------------------------------------------------------------------

const closingIssues = [];

const hasNoVerifiedLinks =
  !closingInfo.baadExhibitionUrl &&
  !closingInfo.baadArtistUrl &&
  !closingInfo.baadGalleryUrl &&
  !closingInfo.artistWebsite &&
  !closingInfo.artistInstagram &&
  !closingInfo.galleryPage &&
  !closingInfo.museumInstitutionPage &&
  !closingInfo.otherRelevantLink;

if (closingInfo.useInDraft === true && hasNoVerifiedLinks) {
  const closingRiskTerms = [
    'learn more',
    'read more',
    'visit ',
    'follow ',
    'instagram',
    'website',
    'tickets',
    'book now',
    'http://',
    'https://',
  ];

  const closingRiskHits = closingRiskTerms.filter((phrase) =>
    draftTextLower.includes(phrase)
  );

  if (closingRiskHits.length > 0) {
    closingIssues.push({
      issue: 'Closing paragraph implies links/actions that are not verified.',
      hits: closingRiskHits,
    });
  }
}

const rawUrlHits = ['http://', 'https://'].filter((phrase) =>
  baadBodyLower.includes(phrase)
);

if (rawUrlHits.length > 0) {
  closingIssues.push({
    issue: 'Article body contains raw URL(s). Use a clean BAAD closing sentence instead of visible URLs.',
    hits: rawUrlHits,
  });
}

// -----------------------------------------------------------------------------
// 8) Decide pass / repair / human review
// -----------------------------------------------------------------------------

const reasons = [];

if (hardBanHits.length > 0) {
  reasons.push(`Hard-ban phrase(s) found: ${hardBanHits.map(h => h.phrase).join(', ')}`);
}

if (unsupportedRiskyHits.length > 0) {
  reasons.push(
    `Unsupported risky phrase(s) found for ${sourceStrength} source: ` +
    unsupportedRiskyHits.map(h => h.phrase).join(', ')
  );
}

if (subtleUnsupportedHits.length > 0) {
  reasons.push(
    `Subtle unsupported phrase(s) found for ${sourceStrength} source: ` +
    subtleUnsupportedHits.map(h => h.phrase).join(', ')
  );
}

if (mechanicalAttributionHits.length > 0) {
  reasons.push(
    `Mechanical attribution phrase(s) found: ` +
    mechanicalAttributionHits.map(h => h.phrase).join(', ')
  );
}

if (missingRequiredFacts.length > 0) {
  reasons.push(
    `Missing required fact(s): ${missingRequiredFacts.map(f => f.label).join(', ')}`
  );
}

if (closingIssues.length > 0) {
  reasons.push(
    `Closing issue(s): ${closingIssues.map(i => i.issue).join('; ')}`
  );
}

const draftPassesValidation =
  hardBanHits.length === 0 &&
  unsupportedRiskyHits.length === 0 &&
  subtleUnsupportedHits.length === 0 &&
  mechanicalAttributionHits.length === 0 &&
  missingRequiredFacts.length === 0 &&
  closingIssues.length === 0;

const validationDecision = draftPassesValidation
  ? 'pass'
  : 'repair';

const validationMessage = draftPassesValidation
  ? 'Draft passed BAAD context-aware validation.'
  : `Draft should be repaired before Airtable update. ${reasons.join(' ')}`;

// -----------------------------------------------------------------------------
// 9) Return enriched draft payload
// -----------------------------------------------------------------------------

return {
  json: {
    ...draft,

    validation: {
      draftPassesValidation,
      validationDecision,
      validationMessage,

      sourceWordCount,
      sourceStrength,
      sourcePacketsApplied,
      sourcePacketsCount,

      hardBanHits,
      riskyPhraseHits: riskyHitsAll,
      unsupportedRiskyHits,
      riskyButSourceSupportedHits,

      subtlePhraseHits: subtleHitsAll,
      subtleUnsupportedHits,
      subtleButSourceSupportedHits,

      mechanicalAttributionHits,

      allowedStyleHits,

      requiredFacts,
      missingRequiredFacts,
      closingIssues,

      articleId: draft.id || promptContext.articleId || buildDraftPromptJson.id || buildDraftPromptJson.articleId || '',
      sourceAnalysisId: draft.sourceAnalysisId || sourceAnalysis.sourceAnalysisId || '',
      styleBlueprintName: draft.styleBlueprintName || styleBlueprint.blueprintName || '',
      styleBlueprintRecordId: draft.styleBlueprintRecordId || styleBlueprint.recordId || '',
      closingInfoApplied: draft.closingInfoApplied === true,
      closingInfoRecordId: draft.closingInfoRecordId || workflow.closingInfoRecordId || '',
    },

    draftPassesValidation,
    validationDecision,
    validationMessage,
  },
};

// Prepare Source Packet Lookup
// Adds a stable Airtable Article record ID for BAAD Source Packet retrieval.
// Important: $json.id may be a Style Blueprint ID at this stage, so do not use it first.

const articleId =
  $json.articleId ||
  $json.fullArticleRecordId ||
  $json.articleRecordId ||
  $json.recordId ||
  $json.articleFields?.id ||
  $json.fullArticleFields?.id ||
  $json.validation?.articleId ||
  '';

if (!articleId) {
  throw new Error(
    'Could not find Airtable Article record ID for Source Packet lookup. Expected $json.articleId, $json.fullArticleRecordId, or equivalent.'
  );
}

return {
  json: {
    ...$json,
    sourcePacketArticleId: articleId,
  },
};

// Attach Source Packets to Draft Context
// Combines the original draft context with approved BAAD Source Packets
// and classifies each packet by editorial draft role.

const contextItems = $items('Prepare Source Packet Lookup');
const originalContext = contextItems?.[0]?.json || {};

function asBool(value) {
  return value === true || value === 1 || value === '1' || String(value).toLowerCase() === 'true';
}

function asText(value) {
  if (Array.isArray(value)) {
    return value.map(asText).filter(Boolean).join('\n\n');
  }
  if (value && typeof value === 'object') {
    return Object.values(value).map(asText).filter(Boolean).join('\n\n');
  }
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function parsePacketJson(value) {
  if (!value) return {};
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(String(value));
  } catch (error) {
    return {};
  }
}

function extractRecommendedDraftUse(fields, packetJson, editorialUseNotes) {
  const direct =
    fields['Recommended Draft Use'] ||
    fields['Recommended draft use'] ||
    packetJson.recommendedDraftUse ||
    packetJson.openAiAnalysis?.recommendedDraftUse ||
    '';

  if (direct) return String(direct).trim();

  const match = String(editorialUseNotes || '').match(/Recommended draft use:\s*([\w-]+)/i);
  return match?.[1] ? match[1].trim() : '';
}

function normalise(value) {
  return String(value || '').trim().toLowerCase();
}

function classifyPacket(packet) {
  const sourceType = normalise(packet.sourceType);
  const draftUse = normalise(packet.recommendedDraftUse);
  const priority = normalise(packet.priority);
  const name = normalise(packet.name + ' ' + packet.sourcePublisher + ' ' + packet.sourceTitle);

  const roles = new Set();

  const officialTypes = [
    'gallery press release',
    'gallery exhibition page',
    'museum page',
    'institution page',
    'artwork page',
    'baad internal reference',
  ];

  const artistVoiceTypes = [
    'artist interview',
    'artist statement',
    'artist bio',
  ];

  const externalTypes = [
    'additional article',
    'review',
    'catalogue text',
  ];

  if (officialTypes.includes(sourceType)) roles.add('factual_skeleton');
  if (artistVoiceTypes.includes(sourceType)) roles.add('artist_voice');
  if (externalTypes.includes(sourceType)) roles.add('external_interpretation');
  if (sourceType === 'artist bio') roles.add('context');
  if (sourceType === 'catalogue text') roles.add('context');
  if (packet.useForClosing) roles.add('closing');
  if (packet.useForQuotes || packet.quoteCandidates || draftUse === 'artist_voice') roles.add('quote_pool');

  if (draftUse === 'factual_skeleton' || draftUse === 'official_facts' || draftUse === 'official_context' || priority === 'primary') {
    roles.add('factual_skeleton');
  }

  if (draftUse === 'artist_voice' || draftUse === 'quotes' || draftUse === 'quote_pool') {
    roles.add('artist_voice');
    roles.add('quote_pool');
  }

  if (draftUse === 'material_process' || draftUse === 'materials' || draftUse === 'process' || packet.editorialUseNotes.toLowerCase().includes('material / process details')) {
    roles.add('material_process');
  }

  if (draftUse === 'context' || draftUse === 'background' || draftUse === 'external_context') {
    roles.add('context');
  }

  if (draftUse === 'external_interpretation' || packet.rightsCopyingRisk.toLowerCase() === 'high') {
    roles.add('external_interpretation');
  }

  if (name.includes('wallpaper') && sourceType === 'artist interview') {
    roles.add('artist_voice');
    roles.add('quote_pool');
    roles.add('external_interpretation');
  }

  if (name.includes('cristea roberts')) {
    roles.add('factual_skeleton');
  }

  if (!roles.size) roles.add('context');
  return Array.from(roles);
}

function formatPacket(packet, index) {
  return [
    'SOURCE PACKET ' + (index + 1) + ': ' + packet.name,
    'Packet ID: ' + packet.id,
    'Draft Role(s): ' + packet.roles.join(', '),
    'Recommended Draft Use: ' + (packet.recommendedDraftUse || '[Not specified]'),
    'Source Type: ' + packet.sourceType,
    'Publisher: ' + packet.sourcePublisher,
    'Title: ' + packet.sourceTitle,
    'Priority: ' + packet.priority,
    'Reliability: ' + packet.sourceReliability,
    'Rights / Copying Risk: ' + packet.rightsCopyingRisk,
    'Avoid Copying?: ' + (packet.avoidCopying ? 'Yes' : 'No'),
    '',
    'PROMPT-READY EXTRACT:',
    packet.promptReadyExtract || '[No prompt-ready extract provided]',
    '',
    'VERIFIED FACTS:',
    packet.verifiedFacts || '[No verified facts provided]',
    '',
    'SOURCE MEANING TO RECAST:',
    packet.sourceMeaningToRecast || '[No source meaning notes provided]',
    '',
    'MATERIAL / PROCESS + EDITORIAL USE NOTES:',
    packet.editorialUseNotes || '[No editorial notes provided]',
    '',
    'QUOTE CANDIDATES:',
    packet.quoteCandidates || '[No quote candidates provided]',
    '',
    'QUOTE USE NOTES:',
    packet.quoteUseNotes || '[No quote notes provided]',
    '',
    'AVOID COPYING NOTES:',
    packet.avoidCopyingNotes || '[No avoid-copying notes provided]',
  ].join('\n');
}

const packets = items
  .map((item) => {
    const json = item.json || {};
    const fields = json.fields || json;
    const packetJson = parsePacketJson(fields['Packet JSON']);
    const editorialUseNotes = asText(fields['Editorial Use Notes'] || '');

    const packet = {
      id: json.id || '',
      name: fields['Source Packet Name'] || '',
      sourceType: fields['Source Type'] || '',
      sourcePublisher: fields['Source Publisher'] || '',
      sourceTitle: fields['Source Title'] || '',
      sourceUrl: fields['Source URL'] || '',
      priority: fields['Draft Use Priority'] || '',
      useInDraft: asBool(fields['Use in Draft?']),
      useForQuotes: asBool(fields['Use for Quotes?']),
      useForClosing: asBool(fields['Use for Closing?']),
      avoidCopying: asBool(fields['Avoid Copying?']),
      sourceReliability: fields['Source Reliability'] || '',
      rightsCopyingRisk: fields['Rights / Copying Risk'] || '',
      recommendedDraftUse: extractRecommendedDraftUse(fields, packetJson, editorialUseNotes),
      promptReadyExtract: asText(fields['Prompt-Ready Extract'] || ''),
      verifiedFacts: asText(fields['Verified Facts'] || ''),
      quoteCandidates: asText(fields['Quote Candidates'] || ''),
      quoteUseNotes: asText(fields['Quote Use Notes'] || ''),
      sourceMeaningToRecast: asText(fields['Source Meaning to Recast'] || ''),
      avoidCopyingNotes: asText(fields['Avoid Copying Notes'] || ''),
      editorialUseNotes,
      humanReviewNotes: asText(fields['Human Review Notes'] || ''),
      articleRecordId: fields['Article Record ID'] || '',
      sourceRecordId: fields['Source Record ID'] || '',
    };

    packet.roles = classifyPacket(packet);
    packet.primaryRole = packet.roles[0] || 'context';
    return packet;
  })
  .filter((packet) => packet.id || packet.name || packet.promptReadyExtract);

const roleGroups = {
  factualSkeletonPackets: packets.filter(packet => packet.roles.includes('factual_skeleton')),
  artistVoicePackets: packets.filter(packet => packet.roles.includes('artist_voice')),
  materialProcessPackets: packets.filter(packet => packet.roles.includes('material_process')),
  contextPackets: packets.filter(packet => packet.roles.includes('context')),
  externalInterpretationPackets: packets.filter(packet => packet.roles.includes('external_interpretation')),
  quotePackets: packets.filter(packet => packet.roles.includes('quote_pool')),
  closingPackets: packets.filter(packet => packet.roles.includes('closing')),
  highCopyingRiskPackets: packets.filter(packet =>
    packet.avoidCopying ||
    normalise(packet.rightsCopyingRisk) === 'high' ||
    packet.roles.includes('external_interpretation')
  ),
};

const sourcePacketsForPrompt = packets.map(formatPacket).join('\n\n---\n\n');

const sourcePacketRoleGuide = [
  'SOURCE PACKET ROLE SUMMARY:',
  'Total approved packets: ' + packets.length,
  'Factual skeleton packets: ' + (roleGroups.factualSkeletonPackets.map(p => p.name).filter(Boolean).join('; ') || 'None'),
  'Artist voice packets: ' + (roleGroups.artistVoicePackets.map(p => p.name).filter(Boolean).join('; ') || 'None'),
  'Material/process packets: ' + (roleGroups.materialProcessPackets.map(p => p.name).filter(Boolean).join('; ') || 'None'),
  'Context packets: ' + (roleGroups.contextPackets.map(p => p.name).filter(Boolean).join('; ') || 'None'),
  'External interpretation / high-copying-risk packets: ' + (roleGroups.externalInterpretationPackets.map(p => p.name).filter(Boolean).join('; ') || 'None'),
  'Quote packets: ' + (roleGroups.quotePackets.map(p => p.name).filter(Boolean).join('; ') || 'None'),
  'Closing packets: ' + (roleGroups.closingPackets.map(p => p.name).filter(Boolean).join('; ') || 'None'),
].join('\n');

return [
  {
    json: {
      ...originalContext,
      sourcePacketsApplied: packets.length > 0,
      sourcePacketsCount: packets.length,
      sourcePackets: packets,
      sourcePacketsForPrompt,
      sourcePacketRoles: roleGroups,
      sourcePacketRoleGuide,
    },
  },
];

return {
  json: {
    fields: {},
    sourceAnalysisId: '',
    sourceAnalysisCreatedTime: '',
    sourceAnalysisFallback: true,
  },
};
